# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  INDICADORES DE MERCADO - automГЎticos para el header
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
@st.cache_data(ttl=900, show_spinner=False)  # cache 15 min
def fetch_market_indicators() -> dict:
    """
    Descarga indicadores clave de mercado para el header.
    Todos relevantes para el modelo de rebote tГ©cnico NBIS.
    """
    result = {}
    try:
        import yfinance as yf

        # S&P 500
        try:
            spx = yf.Ticker("^GSPC").history(period="5d")
            if not spx.empty:
                _spx_c = spx["Close"].dropna()
                if len(_spx_c) >= 1:
                    spx_now  = float(_spx_c.iloc[-1])
                    spx_prev = float(_spx_c.iloc[-2]) if len(_spx_c) >= 2 else spx_now
                    if spx_now == spx_now and spx_now > 0:  # NaN check
                        result["spx"] = {"val": spx_now, "chg": (spx_now-spx_prev)/spx_prev*100}
        except Exception: pass

        # Nasdaq
        try:
            ndx = yf.Ticker("^IXIC").history(period="5d")
            if not ndx.empty:
                _ndx_c = ndx["Close"].dropna()
                if len(_ndx_c) >= 1:
                    ndx_now  = float(_ndx_c.iloc[-1])
                    ndx_prev = float(_ndx_c.iloc[-2]) if len(_ndx_c) >= 2 else ndx_now
                    if ndx_now == ndx_now and ndx_now > 0:  # NaN check
                        result["ndx"] = {"val": ndx_now, "chg": (ndx_now-ndx_prev)/ndx_prev*100}
        except Exception: pass

        # Fear & Greed aproximado via VIX (^PCALL no disponible en Yahoo)
        try:
            # Usar VIX como proxy de Fear & Greed
            vix_fg = yf.Ticker("^VIX").history(period="2d")
            if not vix_fg.empty:
                vix_val = float(vix_fg["Close"].iloc[-1])
                if vix_val >= 35:
                    fg_label = "MIEDO EXTREMO рҹҹў"; fg_score = 15; fg_color = "G"
                elif vix_val >= 25:
                    fg_label = "MIEDO рҹҹЎ"; fg_score = 30; fg_color = "A"
                elif vix_val >= 18:
                    fg_label = "NEUTRAL вҡӘ"; fg_score = 50; fg_color = "TXT_MUT"
                elif vix_val >= 13:
                    fg_label = "CODICIA рҹҹЎ"; fg_score = 70; fg_color = "A"
                else:
                    fg_label = "CODICIA EXTREMA рҹ”ҙ"; fg_score = 85; fg_color = "R"
                result["pcr"] = {"val": round(vix_val,1), "label": fg_label,
                                 "score": fg_score, "color_key": fg_color}
        except Exception:
            pass

        # SPY completo: RSI + EMA50 + EMA200 + MACD tendencia + cambio 20d
        try:
            spy = yf.Ticker("SPY").history(period="1y")
            if not spy.empty:
                s = spy["Close"].dropna()  # eliminar NaN (pre/after-hours, dГӯas sin datos)
                if len(s) >= 21:
                    _pa_spy   = float(s.iloc[-1])
                    _p20_spy  = float(s.iloc[-20]) if len(s)>=20 else _pa_spy
                    _chg20    = round((_pa_spy-_p20_spy)/_p20_spy*100, 1)
                # RSI
                delta = s.diff()
                gain  = delta.clip(lower=0).rolling(14).mean()
                loss  = (-delta.clip(upper=0)).rolling(14).mean()
                rsi_spy = round(float(100-100/(1+gain.iloc[-1]/(loss.iloc[-1]+1e-9))), 1)
                # EMA50 y EMA200
                ema50_spy  = float(s.ewm(span=50,  adjust=False).mean().iloc[-1])
                ema200_spy = float(s.ewm(span=200, adjust=False).mean().iloc[-1])
                # MACD tendencia (12/26) y seГұal (9)
                ema12 = s.ewm(span=12, adjust=False).mean()
                ema26 = s.ewm(span=26, adjust=False).mean()
                macd_line   = ema12 - ema26
                macd_signal = macd_line.ewm(span=9, adjust=False).mean()
                macd_now    = float(macd_line.iloc[-1])
                macd_sig    = float(macd_signal.iloc[-1])
                macd_prev   = float(macd_line.iloc[-2]) if len(macd_line)>=2 else macd_now
                macd_cruce  = "positivo" if macd_now > macd_sig else "negativo"
                macd_dir    = "subiendo" if macd_now > macd_prev else "bajando"
                # VIX tendencia (necesita descarga separada de 5d)
                result["spy"] = {
                    "rsi":       rsi_spy,
                    "precio":    round(_pa_spy, 2),
                    "chg_20d":   _chg20,
                    "sobre_ema50":  _pa_spy > ema50_spy,
                    "sobre_ema200": _pa_spy > ema200_spy,
                    "dist_ema200":  round((_pa_spy - ema200_spy)/ema200_spy*100, 1),
                    "macd_cruce":   macd_cruce,
                    "macd_dir":     macd_dir,
                    "ema_status": "SPY sobre EMA200" if _pa_spy > ema200_spy else "SPY BAJO EMA200",
                }
        except Exception: pass

        # VIX tendencia (7d)
        try:
            vix_hist = yf.Ticker("^VIX").history(period="1mo")
            if not vix_hist.empty and len(vix_hist) >= 7:
                _vix_now  = float(vix_hist["Close"].iloc[-1])
                _vix_7d   = float(vix_hist["Close"].iloc[-7])
                _vix_chg  = round(_vix_now - _vix_7d, 1)
                result["vix_trend"] = {"valor": round(_vix_now,1), "chg_7d": _vix_chg,
                                       "subiendo": _vix_chg > 2}
        except Exception: pass

        # Sector mГЎs dГ©bil - buscar el que tiene mГЎs acciones en correcciГіn
        sectores = {
            "EnergГӯa":   ["XOM","CVX","OXY","DVN","COP"],
            "Tech":      ["MSFT","GOOGL","META","NVDA","AMD"],
            "Salud":     ["PFE","MRNA","ABBV","MRK","GILD"],
            "Finanzas":  ["JPM","BAC","GS","MS","C"],
            "Consumo":   ["NKE","CROX","SBUX","MCD","TGT"],
            "Industrial":["BA","GE","HON","CAT","DE"],
        }
        sector_scores = {}
        for sector, tickers in sectores.items():
            en_correccion = 0
            for tk in tickers:
                try:
                    import time as _tm_scan
                    _tm_scan.sleep(0.08)  # anti rate-limit
                    h = yf.Ticker(tk).history(period="3mo")
                    if h.empty: continue
                    c2 = h["Close"].values
                    precio = float(c2[-1]); pico = float(c2.max())
                    dd = (precio-pico)/pico*100
                    s2 = __import__("pandas").Series(c2)
                    d2 = s2.diff()
                    g2 = d2.clip(lower=0).rolling(14).mean()
                    l2 = (-d2.clip(upper=0)).rolling(14).mean()
                    rsi2 = float(100-100/(1+g2.iloc[-1]/(l2.iloc[-1]+1e-9)))
                    if rsi2 < 50 and dd < -10:
                        en_correccion += 1
                except Exception: continue
            sector_scores[sector] = en_correccion

        if sector_scores:
            mejor_sector = max(sector_scores, key=sector_scores.get)
            result["sectores"] = {
                "mejor_oportunidad": mejor_sector,
                "acciones_en_correccion": sector_scores[mejor_sector],
                "scores": sector_scores,
            }

    except Exception: pass
    return result


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  UNIVERSO A ESCANEAR - S&P500 + Nasdaq + Sectores
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  PRE/POST MARKET - datos en tiempo real por ticker
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
@st.cache_data(ttl=300, show_spinner=False)  # cache 5 min
def fetch_pre_post(ticker: str) -> dict:
    """
    Obtiene Pre-Market y Post-Market de yfinance.
    Si no hay datos, retorna dict con valores None.
    """
    result = {
        "pre_price":  None, "pre_chg":   None, "pre_vol":  None,
        "post_price": None, "post_chg":  None, "post_vol": None,
        "vol_hoy":    None, "vol_avg20": None, "vol_ratio": None,
        "precio_reg": None,
    }
    try:
        import yfinance as yf
        tk = yf.Ticker(ticker)

        # Fast info - precio regular, pre y post
        try:
            fi = tk.fast_info
            result["precio_reg"] = float(fi.last_price) if fi.last_price else None

            # Pre-Market
            if hasattr(fi, "pre_market_price") and fi.pre_market_price:
                result["pre_price"] = float(fi.pre_market_price)
                if result["precio_reg"]:
                    result["pre_chg"] = round(
                        (result["pre_price"] - result["precio_reg"]) / result["precio_reg"] * 100, 2)

            # Post-Market
            if hasattr(fi, "post_market_price") and fi.post_market_price:
                result["post_price"] = float(fi.post_market_price)
                if result["precio_reg"]:
                    result["post_chg"] = round(
                        (result["post_price"] - result["precio_reg"]) / result["precio_reg"] * 100, 2)
        except Exception:
            pass

        # Volumen hoy vs promedio 20 dГӯas
        try:
            hist = tk.history(period="1mo")
            if not hist.empty and len(hist) >= 5:
                import numpy as np
                avg20 = float(np.mean(hist["Volume"].values[-20:]))
                vol_hoy = float(hist["Volume"].values[-1])
                result["vol_hoy"]   = int(vol_hoy)
                result["vol_avg20"] = int(avg20)
                result["vol_ratio"] = round(vol_hoy / avg20 * 100, 0) if avg20 > 0 else None
        except Exception:
            pass

    except Exception:
        pass
    return result

def render_pre_post_bar(ticker: str, precio_actual: float,
                        G: str, A: str, R: str,
                        TXT_MUT: str, TXT_SOFT: str,
                        BG_HEAD: str, BOR: str) -> str:
    """
    v18: Pre/Post Market con interpretaciГіn de trader.
    No solo muestra el % вҖ” explica quГ© hacer con el gap.
    """
    d = fetch_pre_post(ticker)

    def vol_semaforo(ratio):
        if ratio is None: return "вҡӘ", TXT_MUT, "Sin datos"
        if ratio >= 200:  return "рҹҹў", G,       f"{ratio:.0f}% вҖ” institucional"
        if ratio >= 120:  return "рҹҹЎ", A,        f"{ratio:.0f}% вҖ” normal"
        return "рҹ”ҙ", R, f"{ratio:.0f}% вҖ” bajo"

    def chg_semaforo(chg):
        if chg is None:  return "вҡӘ", TXT_MUT, "Sin datos"
        if chg >= 5:     return "рҹ”ҙ", R,       f"+{chg:.1f}% вҖ” gap extremo"
        if chg >= 2:     return "рҹҹЎ", A,        f"+{chg:.1f}% вҖ” gap moderado"
        if chg >= 0.5:   return "рҹҹў", G,       f"+{chg:.1f}% вҖ” positivo"
        if chg >= -0.5:  return "вҡӘ", TXT_MUT, f"{chg:.1f}% вҖ” plano"
        if chg >= -2:    return "рҹҹЎ", A,        f"{chg:.1f}% вҖ” leve baja"
        return "рҹ”ҙ", R, f"{chg:.1f}% вҖ” gap negativo"

    # в”Җв”Җ InterpretaciГіn del gap (la parte nueva v18) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    def interpretar_gap(chg, vol_ratio) -> tuple:
        """
        Retorna (semaforo, consejo) segГәn el tipo de gap.
        Basado en las 5 reglas del pre-market.
        """
        if chg is None:
            return "вҡӘ", "Sin datos pre-market disponibles"

        abs_chg = abs(chg)

        if abs_chg > 8:
            return ("рҹҡ«",
                "Gap extremo (>8%) вҖ” tierra de nadie. "
                "Primeros 30 min son muy volГЎtiles. "
                "Esperar que el precio se estabilice antes de entrar. "
                "Caso IREN hoy: abriГі +8%, oscilГі $18 en el dГӯa.")
        elif abs_chg > 5:
            return ("вҡ пёҸ",
                f"Gap {'positivo' if chg>0 else 'negativo'} fuerte ({chg:+.1f}%). "
                "Regla: esperar 15-30 min y ver si MANTIENE el nivel. "
                "Si el precio del primer minuto > precio pre-market вҶ’ fuerza real. "
                "Si retrocede en los primeros minutos вҶ’ no perseguir.")
        elif abs_chg > 2:
            return ("рҹҹЎ",
                f"Gap moderado ({chg:+.1f}%). "
                "VГЎlido si la acciГіn ya estaba en M2/M3 antes del gap. "
                "Confirmar con volumen: si Vol > 150% del promedio вҶ’ seГұal real. "
                f"Volumen actual: {vol_ratio:.0f}% del promedio." if vol_ratio else
                f"Gap moderado ({chg:+.1f}%). Confirmar con volumen al abrir.")
        elif chg > 0.3:
            return ("вң…",
                f"Gap de continuaciГіn ({chg:+.1f}%). "
                "Tipo mГЎs seguro para entrar. "
                "Si la acciГіn tiene seГұal M2/M3 y el gap es pequeГұo вҶ’ "
                "puede entrar en apertura o en el primer pull-back.")
        elif chg > -0.3:
            return ("вҡӘ", "Sin gap significativo вҖ” acciГіn abre plana.")
        else:
            return ("рҹ”ҙ",
                f"Gap negativo ({chg:+.1f}%). "
                "SeГұal de debilidad. Si tenГӯas posiciГіn вҶ’ "
                "revisar si el motivo de la baja cambia la tesis.")

    pre_ico,  pre_c,  pre_txt  = chg_semaforo(d["pre_chg"])
    post_ico, post_c, post_txt = chg_semaforo(d["post_chg"])
    vol_ico,  vol_c,  vol_txt  = vol_semaforo(d["vol_ratio"])

    # Gap activo вҖ” pre-market si hay datos, sino post-market
    gap_activo = d["pre_chg"] if d["pre_chg"] is not None else d["post_chg"]
    gap_ico, gap_consejo = interpretar_gap(gap_activo, d["vol_ratio"] or 100)
    es_pre = d["pre_chg"] is not None
    gap_label = "PRE-MARKET" if es_pre else "POST-MARKET"

    pre_precio  = f"${d['pre_price']:.2f}"  if d["pre_price"]  else "вҖ”"
    post_precio = f"${d['post_price']:.2f}" if d["post_price"] else "вҖ”"

    # Color del panel de interpretaciГіn
    if gap_ico == "рҹҡ«":
        panel_bg, panel_bor, panel_c = "#FEF2F2", "#FCA5A5", "#DC2626"
    elif gap_ico == "вҡ пёҸ":
        panel_bg, panel_bor, panel_c = "#FFFBEB", "#FCD34D", "#D97706"
    elif gap_ico == "вң…":
        panel_bg, panel_bor, panel_c = "#F0FDF4", "#86EFAC", "#16A34A"
    else:
        panel_bg, panel_bor, panel_c = BG_HEAD, BOR, TXT_MUT

    html = (
        f'<div style="margin-top:8px">'
        # Fila superior: Pre / Post / Volumen
        f'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;margin-bottom:6px">'
        # Pre-Market
        f'<div style="background:{BG_HEAD};border:1px solid {BOR};border-radius:8px;padding:7px 10px">'
        f'<div style="font-size:9px;color:{TXT_MUT};font-weight:700;margin-bottom:2px">PRE-MARKET</div>'
        f'<div style="font-size:13px;font-weight:700;color:{pre_c}">{pre_ico} {pre_precio}</div>'
        f'<div style="font-size:10px;color:{pre_c}">{pre_txt}</div>'
        f'</div>'
        # Post-Market
        f'<div style="background:{BG_HEAD};border:1px solid {BOR};border-radius:8px;padding:7px 10px">'
        f'<div style="font-size:9px;color:{TXT_MUT};font-weight:700;margin-bottom:2px">POST-MARKET</div>'
        f'<div style="font-size:13px;font-weight:700;color:{post_c}">{post_ico} {post_precio}</div>'
        f'<div style="font-size:10px;color:{post_c}">{post_txt}</div>'
        f'</div>'
        # Volumen
        f'<div style="background:{BG_HEAD};border:1px solid {BOR};border-radius:8px;padding:7px 10px">'
        f'<div style="font-size:9px;color:{TXT_MUT};font-weight:700;margin-bottom:2px">VOL HOY</div>'
        f'<div style="font-size:13px;font-weight:700;color:{vol_c}">{vol_ico} {d["vol_ratio"]:.0f}%</div>'
        f'<div style="font-size:10px;color:{vol_c}">{vol_txt.split(" вҖ” ")[1] if " вҖ” " in vol_txt else vol_txt}</div>'
        f'</div>'
        f'</div>'
        # Panel de interpretaciГіn del trader
        + (
        f'<div style="background:{panel_bg};border:1px solid {panel_bor};'
        f'border-radius:8px;padding:8px 12px">'
        f'<div style="font-size:10px;font-weight:800;color:{panel_c};margin-bottom:3px">'
        f'{gap_ico} {gap_label} вҖ” InterpretaciГіn del trader</div>'
        f'<div style="font-size:10px;color:#374151;line-height:1.5">{gap_consejo}</div>'
        f'</div>'
        if gap_activo is not None else ""
        )
        + f'</div>'
    )
    return html


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  PANEL PROBABILIDAD NBIS - para todas las tarjetas del scanner
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ


@st.cache_data(ttl=600, show_spinner=False)
def leer_watchlist_sheets() -> "pd.DataFrame | None":
    """
    v18: Lee GrekoTrader_Watchlist desde Google Sheets.
    Columnas: Ticker | Nombre | Area | Nota
    """
    try:
        svc = _get_sheets_service()
        if not svc:
            st.session_state["_wl_sheets_error"] = "P1_FAIL: sin credenciales gcp_service_account"
            return None

        sheet_id = _get_sheet_id_from_secrets("watchlist_id")
        if not sheet_id:
            st.session_state["_wl_sheets_error"] = "P2_FAIL: watchlist_id no encontrado en st.secrets[sheets]"
            return None

        rows = []
        for _nombre_hoja in ["Hoja 1", "Sheet1", "Watchlist", "Hoja1", "Sheet 1"]:
            try:
                _result = svc.spreadsheets().values().get(
                    spreadsheetId=sheet_id,
                    range=f"'{_nombre_hoja}'!A1:Z5000"
                ).execute()
                _vals = _result.get("values", [])
                if _vals:
                    rows = _vals
                    st.session_state["_wl_sheets_error"] = ""
                    st.session_state["_wl_sheets_hoja"] = _nombre_hoja
                    break
            except Exception:
                continue

        if not rows:
            try:
                _result = svc.spreadsheets().values().get(
                    spreadsheetId=sheet_id, range="A1:Z5000"
                ).execute()
                rows = _result.get("values", [])
                st.session_state["_wl_sheets_hoja"] = "rango genГ©rico"
            except Exception as _e3:
                st.session_state["_wl_sheets_error"] = f"P3_FAIL: {str(_e3)[:100]}"
                return None

        if len(rows) < 2:
            st.session_state["_wl_sheets_error"] = "P4_WARN: Sheet vacГӯo o solo tiene headers вҖ” agrega tickers en filas 2+"
            return pd.DataFrame(columns=["Ticker","Nombre","Area","Nota"])

        headers = [h.strip() for h in rows[0]]
        _n_raw = len(rows) - 1
        wl_data = []
        _n_sin_ticker = 0
        _n_vacias = 0
        for row in rows[1:]:
            if not row:
                _n_vacias += 1
                continue
            d = {headers[i]: row[i] if i < len(row) else "" for i in range(len(headers))}
            tk = str(d.get("Ticker", d.get("Ticket", d.get("TICKER", d.get("TICKET", ""))))).upper().strip().replace("$","").replace(" ","")
            if not tk:
                _n_sin_ticker += 1
                continue
            wl_data.append({
                "Ticker": tk,
                "Nombre": str(d.get("Nombre", tk)).strip(),
                "Area":   str(d.get("Area", d.get("ГҒrea", d.get("Sector", "-")))).strip(),
                "Nota":   str(d.get("Nota",  d.get("Notas", ""))).strip(),
            })
        _hoja_usada = st.session_state.get("_wl_sheets_hoja", "?")
        _n_validos = len(wl_data)
        _diag_extra = f" В· {_n_sin_ticker} sin Ticker" if _n_sin_ticker else ""
        st.session_state["_wl_sheets_error"] = (
            f"P5_OK: {_n_validos} filas В· headers={headers[:4]}")
        st.session_state["_wl_sheets_diag"] = {
            "hoja": _hoja_usada, "raw": _n_raw, "validos": _n_validos,
            "sin_ticker": _n_sin_ticker, "vacias": _n_vacias,
        }
        return pd.DataFrame(wl_data) if wl_data else pd.DataFrame(columns=["Ticker","Nombre","Area","Nota"])
    except Exception as _e:
        try:
            st.session_state["_wl_sheets_error"] = f"EXCEPTION: {str(_e)[:120]}"
        except Exception:
            pass
        return None


@st.cache_data(ttl=300, show_spinner=False)
def calcular_seГұal_recompra(
    ticker: str,
    precio_entrada: float,
    pnl_pct: float,
    tipo: str = "Accion",
    cat_fecha: str = "-",     # v19: fecha de earnings para ajustar la lГіgica
) -> dict:
    """
    v19: Calcula si existe oportunidad de recompra para una posiciГіn abierta.
    Ahora considera el contexto de earnings para ajustar la seГұal.

    Escenario A вҖ” Pre-earnings 3-7d + PnL >= 20%:
      вҶ’ Recompra especulativa pequeГұa (20% posiciГіn)
    Escenario B вҖ” Post-earnings precio inflado:
      вҶ’ NO recomprar (catalizador consumido)
    Escenario C вҖ” Post-earnings precio castigado:
      вҶ’ Mantener lГіgica normal de recompra
    """
    # в”Җв”Җ Contexto de earnings antes de hacer cualquier fetch в”Җв”Җв”Җв”Җв”Җ
    _earn_ctx = {"dias": None, "tipo": "sin_earnings"}
    if cat_fecha and cat_fecha not in ("-","","nan","NaT"):
        try:
            import datetime as _dt_rc
            _dias_rc = (_dt_rc.date.fromisoformat(str(cat_fecha)[:10])
                        - _dt_rc.date.today()).days
            _earn_ctx["dias"] = _dias_rc
            if 3 <= _dias_rc <= 7:
                _earn_ctx["tipo"] = "pre_earnings"
            elif -3 <= _dias_rc <= 0:
                _earn_ctx["tipo"] = "post_earnings"
        except Exception:
            pass
    try:
        import yfinance as _yf_r
        import numpy as _np_r
        import pandas as _pd_r

        hist = _yf_r.Ticker(ticker).history(period="2mo")
        if hist.empty or len(hist) < 14:
            return {"seГұal": "sin_datos"}

        close = hist["Close"].values
        # v19.1: Divergencia alcista RSI vs precio
        _div_fetch = calcular_divergencia_rsi(close, periodos=14, ventana=20)
        vol   = hist["Volume"].values

        # RSI 14
        s = _pd_r.Series(close)
        delta = s.diff()
        gain  = delta.clip(lower=0).rolling(14).mean()
        loss  = (-delta.clip(upper=0)).rolling(14).mean()
        rsi   = round(float(100 - 100/(1 + gain.iloc[-1]/(loss.iloc[-1]+1e-9))), 1)

        # RSI hace 3 dГӯas (para detectar direcciГіn)
        rsi_3d = round(float(100 - 100/(1 + gain.iloc[-4]/(loss.iloc[-4]+1e-9))), 1)
        rsi_baja = rsi < rsi_3d  # True si RSI bajando

        # EMA20 y precio actual
        ema20 = float(s.ewm(span=20).mean().iloc[-1])
        precio_actual = float(close[-1])
        sobre_ema20 = precio_actual >= ema20 * 0.97  # margen 3%

        # MГЎximo reciente (Гәltimos 12 dГӯas)
        max_rec = float(_np_r.max(close[-12:]))
        dd_max  = round((precio_actual - max_rec) / max_rec * 100, 1)

        # Volumen: bajando en la correcciГіn = sano
        avg_vol  = float(_np_r.mean(vol[-20:]))
        vol_hoy  = float(vol[-1])
        vol_bajo = vol_hoy < avg_vol * 0.9  # vol bajo = pullback sano

        # в”Җв”Җ v19.1: Price Target check ANTES de evaluar recompra в”Җв”Җв”Җв”Җ
        # Si el precio estГЎ sobre el target de analistas вҶ’ NO recomprar
        _pt_rec = get_price_targets(ticker)
        _pt_alerta = ""
        _pt_bloquear_recompra = False

        if _pt_rec.get("ok"):
            _tm_rec  = _pt_rec.get("target_mean", 0)
            _tmax_rec = _pt_rec.get("target_max", 0)
            _na_rec  = _pt_rec.get("n_analysts", 0)
            _up_mean_rec = round((_tm_rec - precio_actual) / precio_actual * 100, 1) if _tm_rec > 0 and precio_actual > 0 else 0
            _up_max_rec  = round((_tmax_rec - precio_actual) / precio_actual * 100, 1) if _tmax_rec > 0 and precio_actual > 0 else 0

            if _na_rec >= 3:
                if precio_actual > _tmax_rec > 0:
                    # Precio sobre el target MГҒXIMO вҖ” bloquear recompra
                    _pt_alerta = (f"рҹҡ« Precio ${precio_actual:.2f} SOBRE target mГЎximo "
                                  f"${_tmax_rec:.0f} de analistas ({_na_rec} analistas) В· "
                                  f"Sin upside segГәn consenso")
                    _pt_bloquear_recompra = True

                elif precio_actual > _tm_rec > 0:
                    # Precio sobre target promedio вҖ” advertencia
                    _pt_alerta = (f"вҡ пёҸ Precio ${precio_actual:.2f} sobre target promedio "
                                  f"${_tm_rec:.0f} ({_up_mean_rec:+.0f}% downside) В· "
                                  f"{_na_rec} analistas В· Agregar con precauciГіn")

                elif _up_max_rec < 10:
                    # Poco upside incluso al target mГЎximo
                    _pt_alerta = (f"вҡ пёҸ Poco upside al target mГЎximo "
                                  f"${_tmax_rec:.0f} (+{_up_max_rec:.0f}%) В· "
                                  f"Ratio riesgo/beneficio bajo para recompra")

        if _pt_bloquear_recompra:
            return {
                "seГұal":    "no_recomprar",
                "razon":    _pt_alerta,
                "rsi":      rsi,
                "dd_max":   dd_max,
                "pt_alerta": _pt_alerta,
            }

        # v19: DГӯas alcistas consecutivos (detectar rebote activo)
        _dias_alcistas = 0
        for _ci in range(len(close)-1, max(0, len(close)-8), -1):
            if close[_ci] > close[_ci-1]:
                _dias_alcistas += 1
            else:
                break

        # Pre-market proxy: comparar Гәltimo close vs close anterior
        _premia_pct = round((float(close[-1]) - float(close[-2])) / float(close[-2]) * 100, 1)

        # в”Җв”Җ Stops segГәn tipo в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        stop_pct = {
            "Accion":        -7.0,
            "ETF_Sectorial": -12.0,
            "ETF_Indice":    -12.0,
            "ETF_Cripto":    -18.0,
        }.get(tipo, -7.0)

        # в”Җв”Җ ESCENARIO 2: PosiciГіn en PГүRDIDA + rebote activo в”Җв”Җв”Җв”Җв”Җ
        # "Promediar a la baja" cuando el rebote estГЎ confirmado
        if pnl_pct < 0 and pnl_pct >= -20:
            _rebote_ok = (
                _dias_alcistas >= 2 and   # rebote iniciado
                48 <= rsi <= 65 and        # RSI vГЎlido, no cayendo
                sobre_ema20 and            # tendencia no rota
                not rsi_baja               # RSI subiendo
            )
            if _rebote_ok:
                # Calcular precio promedio si agrega 40%
                _agregar_pct = 0.40
                _precio_prom = round(
                    (precio_entrada + precio_actual * _agregar_pct) /
                    (1 + _agregar_pct), 2)
                _stop_comb   = round(_precio_prom * (1 + stop_pct/100), 2)
                _breakeven   = round(_precio_prom * 1.005, 2)  # casi breakeven
                _target      = round(precio_entrada * 1.05, 2) # recuperar + 5%

                return {
                    "seГұal":           "promedio_baja",
                    "calidad":         "REBOTE ACTIVO",
                    "emoji_calidad":   "вҡЎ",
                    "precio_actual":   precio_actual,
                    "precio_promedio": _precio_prom,
                    "stop_combinado":  _stop_comb,
                    "breakeven":       _breakeven,
                    "target":          _target,
                    "rsi":             rsi,
                    "dd_max":          dd_max,
                    "dias_alcistas":   _dias_alcistas,
                    "ema_ok":          sobre_ema20,
                    "vol_bajo":        vol_bajo,
                    "descripcion":     (
                        f"{_dias_alcistas} dГӯas alcistas consecutivos В· "
                        f"RSI {rsi} subiendo В· EMA20 respetada. "
                        f"Agregar 40% reduce precio promedio a ${_precio_prom:.2f}. "
                        f"Stop combinado: ${_stop_comb:.2f} В· "
                        f"Target recuperaciГіn: ${_target:.2f}"
                    ),
                }
            else:
                # Escenario 3: pГ©rdida sin rebote вҖ” no actuar
                _razon_no = (
                    f"RSI {rsi} cayendo" if rsi_baja else
                    f"Solo {_dias_alcistas} dГӯa(s) alcista(s) вҖ” esperar confirmaciГіn" if _dias_alcistas < 2 else
                    "EMA20 rota вҖ” tendencia comprometida" if not sobre_ema20 else
                    f"RSI {rsi} fuera de zona vГЎlida"
                )
                return {
                    "seГұal":  "no_promediar",
                    "razon":  f"PosiciГіn en pГ©rdida {pnl_pct:+.1f}% вҖ” {_razon_no}. "
                              f"Esperar {max(0, 2-_dias_alcistas)} dГӯa(s) mГЎs alcistas antes de agregar.",
                    "rsi":    rsi,
                    "dd_max": dd_max,
                    "dias_alcistas": _dias_alcistas,
                }

        # в”Җв”Җ ESCENARIO 3 extremo: pГ©rdida > -20% вҖ” nunca promediar в”Җв”Җ
        if pnl_pct < -20:
            return {
                "seГұal":  "no_promediar",
                "razon":  f"PГ©rdida {pnl_pct:+.1f}% вҖ” demasiado profunda para promediar. "
                          f"Evaluar salida y re-entrada cuando el precio estabilice.",
                "rsi":    rsi,
                "dd_max": dd_max,
            }

        # в”Җв”Җ Evaluar condiciones в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        cond_pnl      = pnl_pct >= 15

        # в”Җв”Җ v19: Evaluar contexto de earnings PRIMERO в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        _earn_tipo = _earn_ctx.get("tipo","sin_earnings")
        _earn_dias = _earn_ctx.get("dias")

        # Escenario A: Pre-earnings 3-7 dГӯas
        if _earn_tipo == "pre_earnings" and _earn_dias is not None:
            if pnl_pct >= 20:
                # ColchГіn suficiente вҶ’ recompra especulativa pequeГұa
                return {
                    "seГұal":           "recompra_pre_earnings",
                    "calidad":         "ESPECULATIVA",
                    "emoji_calidad":   "вҡЎ",
                    "precio_recompra": round(float(close[-1]), 2),
                    "precio_prom":     round((precio_entrada + float(close[-1]))/2, 2),
                    "stop_combinado":  round(float(close[-1]) * 0.95, 2),  # stop -5% estricto
                    "target":          round(float(close[-1]) * 1.12, 2),
                    "rsi":             rsi,
                    "dd_max":          dd_max,
                    "ema_ok":          sobre_ema20,
                    "descripcion":     (
                        f"Earnings en {_earn_dias}d вҖ” recompra especulativa. "
                        f"PnL original +{pnl_pct:.1f}% actГәa como colchГіn. "
                        f"PosiciГіn mГЎx 20% В· Stop -5% sobre recompra. "
                        f"Si earnings positivo вҶ’ posiciГіn total crece. "
                        f"Si earnings negativo вҶ’ colchГіn protege la original."
                    ),
                }
            else:
                return {
                    "seГұal":  "esperar",
                    "razon":  (f"Earnings en {_earn_dias}d вҖ” PnL {pnl_pct:+.1f}% "
                               f"insuficiente como colchГіn. Necesitas вүҘ20% para "
                               f"asumir el riesgo de un earnings prГіximo."),
                    "rsi":    rsi,
                    "dd_max": dd_max,
                }

        # Escenario B: Post-earnings precio inflado вҶ’ NO recomprar
        if _earn_tipo == "post_earnings":
            _gap_post = float(close[-1]) / float(close[-3]) - 1 if len(close) > 3 else 0
            if rsi > 68 or _gap_post > 0.12:
                return {
                    "seГұal":  "no_recomprar",
                    "razon":  (f"Earnings hace {abs(_earn_dias)}d вҖ” precio subiГі "
                               f"+{_gap_post*100:.0f}% В· RSI {rsi:.0f}. "
                               f"Catalizador consumido en el precio. "
                               f"Esperar correcciГіn a RSI 52-58."),
                    "rsi":    rsi,
                    "dd_max": dd_max,
                }
            # Escenario C: Post-earnings precio castigado вҶ’ lГіgica normal
            # (el precio bajГі post-earnings, es como un pullback sano)
            # вҶ’ continГәa con la lГіgica normal de recompra abajo
        cond_dd       = -20 <= dd_max <= -5
        cond_rsi      = 48 <= rsi <= 62
        cond_ema      = sobre_ema20
        cond_vol      = vol_bajo
        cond_rsi_baja = rsi_baja  # confirmaciГіn pullback

        # Puntaje de calidad de la oportunidad
        puntos = sum([cond_pnl, cond_dd, cond_rsi, cond_ema, cond_vol])

        # в”Җв”Җ Determinar seГұal в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
        if not cond_pnl:
            return {
                "seГұal":      "no_aplica",
                "razon":      f"PnL {pnl_pct:+.1f}% вҖ” necesita вүҘ15% para recomprar con seguridad",
                "rsi":        rsi,
                "dd_max":     dd_max,
                "ema_ok":     sobre_ema20,
            }

        if cond_pnl and cond_dd and cond_rsi and cond_ema:
            # SeГұal vГЎlida вҖ” calcular precios
            precio_recompra = round(precio_actual, 2)
            precio_prom = round((precio_entrada + precio_recompra) / 2, 2)
            stop_combinado = round(precio_prom * (1 + stop_pct/100), 2)
            target = round(precio_recompra * 1.15, 2)  # +15% desde recompra

            calidad = "ALTA" if puntos >= 5 else "MEDIA" if puntos >= 4 else "BAJA"
            emoji_cal = "рҹҹў" if calidad == "ALTA" else "рҹҹЎ" if calidad == "MEDIA" else "рҹҹ "

            return {
                "seГұal":           "recompra",
                "calidad":         calidad,
                "emoji_calidad":   emoji_cal,
                "precio_recompra": precio_recompra,
                "precio_prom":     precio_prom,
                "stop_combinado":  stop_combinado,
                "target":          target,
                "rsi":             rsi,
                "dd_max":          dd_max,
                "ema_ok":          sobre_ema20,
                "vol_bajo":        vol_bajo,
                "max_rec":         round(max_rec, 2),
                "puntos":          puntos,
                "descripcion":     (
                    f"DD {dd_max:.1f}% desde mГЎximo В· RSI {rsi} В· "
                    f"EMA20 {'вң…' if sobre_ema20 else 'вқҢ'} В· "
                    f"Vol {'вҶ“ sano' if vol_bajo else 'вҶ‘ vigilar'}"
                ),
            }

        elif cond_pnl and rsi > 65:
            _razon_ep = (f"RSI {rsi} вҖ” precio en mГЎximos, esperar correcciГіn "
                         f"a zona {round(max_rec*0.92,2)}-{round(max_rec*0.95,2)}")
            if _pt_alerta:
                _razon_ep += f" В· {_pt_alerta}"
            return {
                "seГұal":  "esperar_pullback",
                "razon":  _razon_ep,
                "rsi":    rsi,
                "dd_max": dd_max,
                "target_entrada": round(max_rec * 0.93, 2),
                "pt_alerta": _pt_alerta,
            }

        elif cond_pnl and not cond_ema:
            _razon_ema = f"RompiГі EMA20 (${ema20:.2f}) вҖ” pullback demasiado profundo В· RSI {rsi}"
            if _pt_alerta:
                _razon_ema += f" В· {_pt_alerta}"
            return {
                "seГұal":  "no_recomprar",
                "razon":  _razon_ema,
                "rsi":    rsi,
                "dd_max": dd_max,
                "ema20":  round(ema20, 2),
                "pt_alerta": _pt_alerta,
            }

        elif cond_pnl and dd_max < -20:
            _razon_dd = f"DD {dd_max:.1f}% вҖ” correcciГіn muy profunda, puede seguir bajando"
            if _pt_alerta:
                _razon_dd += f" В· {_pt_alerta}"
            return {
                "seГұal":  "no_recomprar",
                "razon":  _razon_dd,
                "rsi":    rsi,
                "dd_max": dd_max,
                "pt_alerta": _pt_alerta,
            }

        else:
            _razon_esp = f"PnL {pnl_pct:+.1f}% В· RSI {rsi} В· DD {dd_max:.1f}% вҖ” monitorear"
            if _pt_alerta:
                _razon_esp += f" В· {_pt_alerta}"
            return {
                "seГұal":  "esperar",
                "razon":  _razon_esp,
                "rsi":    rsi,
                "dd_max": dd_max,
                "pt_alerta": _pt_alerta,
            }

    except Exception as _e_r:
        return {"seГұal": "error", "razon": str(_e_r)[:60]}





def construir_cartera_global() -> dict:
    """
    v19: Lee las 3 carteras (Greko, MVALLE, Amparito) y construye
    un dict global para cruzar con los scans del dГӯa.
    
    Retorna:
    {
      "NBIS": {"carteras": ["MVALLE"], "pnl": 72.4, "pc": 129.90},
      "APLD": {"carteras": ["Greko","MVALLE"], "pnl": 73.9, "pc": 26.64},
    }
    Solo incluye posiciones ACTIVAS (sin Fecha_Salida).
    Se cachea en session_state por 10 minutos.
    """
    import datetime as _dtcg
    
    # Cache check вҖ” recargar si han pasado >10 min
    _cache = st.session_state.get("_cartera_global_cache", {})
    _ts    = st.session_state.get("_cartera_global_ts")
    if _cache and _ts:
        try:
            _mins = (_dtcg.datetime.now() - _ts).seconds / 60
            if _mins < 10:
                return _cache
        except Exception:
            pass

    _cartera = {}
    
    _SHEETS_CONFIG = [
        (_SHEET_NAME_GREKO,    "Greko"),
        (_SHEET_NAME_MAURI,    "MVALLE"),
        (_SHEET_NAME_AMPARITO, "Amparito"),
    ]

    for _sheet_name, _label in _SHEETS_CONFIG:
        try:
            _df = leer_posiciones_sheets(_sheet_name)
            if _df is None or _df.empty:
                continue
            _df = _normalizar_precios_df(_df)
            
            for _, _row in _df.iterrows():
                _tk  = str(_row.get("Ticker","")).upper().strip()
                _fs  = str(_row.get("Fecha_Salida","-")).strip()
                _pc  = _parse_precio(_row.get("Precio_Compra", 0))
                
                if not _tk or _pc <= 0:
                    continue
                # Solo posiciones abiertas (sin fecha de salida)
                if _fs not in ("-","","nan","NaT","None"):
                    continue
                
                # v19: usar precio del session_state si estГЎ disponible
                # evita llamar yfinance Г— N posiciones al cargar
                _cached_prices = st.session_state.get("_precios_live", {})
                if _tk in _cached_prices:
                    _pa  = _cached_prices[_tk]
                    _pnl = round((_pa - _pc) / _pc * 100, 1)
                else:
                    # Solo llamar yfinance si no tenemos precio en cachГ©
                    try:
                        import yfinance as _yf_cg
                        _pa = float(_yf_cg.Ticker(_tk).history(period="1d")["Close"].iloc[-1])
                        _pnl = round((_pa - _pc) / _pc * 100, 1)
                        # Guardar en cachГ© de precios
                        if "_precios_live" not in st.session_state:
                            st.session_state["_precios_live"] = {}
                        st.session_state["_precios_live"][_tk] = _pa
                    except Exception:
                        _pnl = 0.0
                        _pa  = _pc
                
                if _tk not in _cartera:
                    _cartera[_tk] = {"carteras": [], "pnl": _pnl, "pc": _pc, "pa": _pa}
                if _label not in _cartera[_tk]["carteras"]:
                    _cartera[_tk]["carteras"].append(_label)
                    
        except Exception:
            continue

    st.session_state["_cartera_global_cache"] = _cartera
    st.session_state["_cartera_global_ts"]    = _dtcg.datetime.now()
    return _cartera


def get_badge_cartera(ticker: str, G: str, R: str, A: str) -> str:
    """
    v19: Retorna HTML del badge de cartera para un ticker.
    VacГӯo si no estГЎ en ninguna cartera.
    """
    cartera = st.session_state.get("_cartera_global_cache", {})
    if ticker not in cartera:
        return ""
    
    datos     = cartera[ticker]
    pnl       = datos.get("pnl", 0)
    carteras  = datos.get("carteras", [])
    cart_str  = " y ".join(carteras)
    
    if pnl >= 15:
        color = G
        bg    = "#F0FDF4"
        icono = "рҹ“Ң"
        msg   = f"Ya en {cart_str} ({pnl:+.1f}%) В· ver Recompra"
    elif pnl >= 0:
        color = "#D97706"
        bg    = "#FFFBEB"
        icono = "рҹ“Ң"
        msg   = f"Ya en {cart_str} ({pnl:+.1f}%) В· posiciГіn joven"
    else:
        color = R
        bg    = "#FEF2F2"
        icono = "вҡ пёҸ"
        msg   = f"En {cart_str} ({pnl:+.1f}%) В· NO agregar sin catalizador"

    return (
        f'<div style="background:{bg};border-left:3px solid {color};'
        f'border-radius:0 6px 6px 0;padding:4px 10px;margin-top:3px;'
        f'font-size:10px;font-weight:600;color:{color}">'
        f'{icono} {msg}</div>'
    )

def auto_cargar_noticias(tickers: list, max_tickers: int = 12) -> None:
    """
    v19: Carga noticias automГЎticamente para una lista de tickers
    sin requerir que el usuario presione "Actualizar noticias".
    Usa el cachГ© existente y solo fetcha los que faltan.
    MГЎximo max_tickers para no ralentizar.
    """
    cache = st.session_state.get("noticias_cache", {})
    _pendientes = [tk for tk in tickers[:max_tickers]
                   if tk not in cache or not cache[tk].get("noticias")]
    if not _pendientes:
        return  # todos ya en cachГ©
    for _tk in _pendientes:
        try:
            _noticias = fetch_noticias_ticker(_tk)
            if _noticias:
                if "noticias_cache" not in st.session_state:
                    st.session_state["noticias_cache"] = {}
                st.session_state["noticias_cache"][_tk] = {
                    "noticias": _noticias,
                    "ts": __import__("datetime").datetime.now().strftime("%H:%M")
                }
        except Exception:
            pass


def tipo_pullback(dd: float, rsi: float, ema_d: float, 
                  dias_alcistas: int, vol_ratio: float,
                  tiene_posicion_abierta: bool = False,
                  pnl_pct: float = 0.0) -> dict:
    """
    v19: Clasifica el tipo de pullback y genera mensaje claro para el trader.
    
    Pullback 1 вҖ” CorrecciГіn profunda en tendencia alcista (DD вүӨ -20%)
    Pullback 2 вҖ” CorrecciГіn leve en tendencia activa (DD -8% a -20%)  
    Pullback 3 вҖ” Pullback en posiciГіn abierta (Recompra)
    """
    if tiene_posicion_abierta and pnl_pct >= 5:
        # Pullback 3: posiciГіn abierta con ganancia
        if dd <= -5:
            return {
                "tipo": 3,
                "nombre": "Pullback en posiciГіn abierta",
                "emoji": "рҹ”„",
                "color": "#7C3AED",
                "bg": "#F5F3FF",
                "descripcion": (
                    f"CorrecciГіn {dd:.1f}% en tu posiciГіn ganadora (+{pnl_pct:.1f}%). "
                    f"Oportunidad de recompra si RSI 48-62 y EMA20 se respeta. "
                    f"MГЎximo agregar 30% de la posiciГіn original."
                ),
                "accion": "Ver panel Recompra",
            }
        else:
            return {
                "tipo": 3,
                "nombre": "Pullback en posiciГіn abierta",
                "emoji": "вҸі",
                "color": "#2563EB",
                "bg": "#EFF6FF",
                "descripcion": (
                    f"PosiciГіn con +{pnl_pct:.1f}% de ganancia. "
                    f"AГәn no hay correcciГіn suficiente para recompra. "
                    f"Esperar pullback de al menos -5% desde mГЎximo reciente."
                ),
                "accion": "Mantener posiciГіn",
            }

    if dd <= -20:
        # Pullback 1: correcciГіn profunda
        if rsi >= 48 and dias_alcistas >= 2:
            return {
                "tipo": 1,
                "nombre": "Pullback profundo вҖ” rebote tГ©cnico",
                "emoji": "рҹ”Ҙ",
                "color": "#16A34A",
                "bg": "#F0FDF4",
                "descripcion": (
                    f"CorrecciГіn profunda {dd:.1f}% desde mГЎximo histГіrico. "
                    f"RSI {rsi:.0f} en zona de entrada (48-65). "
                    f"{'EMA20 respetada вҖ” tendencia intacta.' if ema_d >= -15 else 'Precio bajo EMA20 вҖ” vigilar.'} "
                    f"Setup M2/M3 clГЎsico del modelo. WR histГіrico: 65-80%."
                ),
                "accion": "SeГұal M2 vГЎlida вҖ” evaluar entrada",
            }
        else:
            return {
                "tipo": 1,
                "nombre": "Pullback profundo вҖ” rebote aГәn no confirmado",
                "emoji": "рҹ‘Җ",
                "color": "#D97706",
                "bg": "#FFFBEB",
                "descripcion": (
                    f"CorrecciГіn profunda {dd:.1f}% pero rebote no confirmado. "
                    f"RSI {rsi:.0f} {'aГәn bajo (< 48) вҖ” acciГіn sigue dГ©bil.' if rsi < 48 else 'subiendo вҖ” positivo.'} "
                    f"Necesita {max(0, 2-dias_alcistas)} dГӯa(s) mГЎs alcistas para confirmar."
                ),
                "accion": "Radar вҖ” esperar confirmaciГіn",
            }

    elif -20 < dd <= -8:
        # Pullback 2: correcciГіn leve en tendencia activa
        if rsi >= 48 and ema_d >= -10:
            return {
                "tipo": 2,
                "nombre": "Pullback saludable en tendencia activa",
                "emoji": "вҡЎ",
                "color": "#0891B2",
                "bg": "#ECFEFF",
                "descripcion": (
                    f"CorrecciГіn leve {dd:.1f}% en tendencia alcista activa. "
                    f"RSI {rsi:.0f} en zona vГЎlida. "
                    f"EMA20 respetada вҖ” la tendencia sigue intacta. "
                    f"'Buy the dip' clГЎsico. "
                    f"Volumen {'bajo en la correcciГіn вң… вҖ” sano.' if vol_ratio < 80 else 'alto en la correcciГіn вҡ пёҸ вҖ” posible distribuciГіn.'}"
                ),
                "accion": "Entrada vГЎlida con posiciГіn reducida (50-60%)",
            }
        else:
            return {
                "tipo": 2,
                "nombre": "CorrecciГіn leve вҖ” sin confirmaciГіn aГәn",
                "emoji": "рҹ“Ў",
                "color": "#6B7280",
                "bg": "#F9FAFB",
                "descripcion": (
                    f"CorrecciГіn {dd:.1f}% desde mГЎximo. "
                    f"{'RSI ' + str(int(rsi)) + ' bajo zona de entrada (< 48).' if rsi < 48 else ''}"
                    f"{'EMA20 rota вҖ” tendencia comprometida.' if ema_d < -10 else ''} "
                    f"Esperar RSI sobre 48 y EMA20 respetada."
                ),
                "accion": "Radar вҖ” esperar mejor setup",
            }

    return {}  # DD muy pequeГұo (< -8%) вҖ” no es pullback significativo



def calcular_stop_tipo(
    pc: float,              # precio de compra
    tipo: str,              # Accion, ETF_Cripto, ETF_Indice, ETF_Sectorial
    beta: float,            # beta de la acciГіn
    score_entrada: float = 0,
    prob_entrada: float = 0,
    tenia_earnings: bool = False,
    pnl_pct: float = 0,
    pa: float = 0,          # v19 FIX: precio actual para calcular targets reales
) -> dict:
    """
    v19: Calcula el stop loss segГәn 3 tipos:
    
    Stop Normal вҖ” seГұal tГ©cnica limpia (score 40-55, prob 30-50%):
      AcciГіn beta < 1.5: -7%
      AcciГіn beta 1.5-2.5: -10%
      AcciГіn beta > 2.5: -12%
      ETF Sectorial: -12%
      ETF ГҚndice: sin stop (mantener siempre)
      ETF Cripto: -20%
      
    Stop Estricto вҖ” seГұal con riesgo adicional:
      Si Score > 55 o Prob > 50% вҶ’ -5% (seГұal tardГӯa)
      Si entrГі con earnings вҶ’ -5% (riesgo binario)
      Si RSI > 65 al entrar вҶ’ -5%
      
    Stop Trailing вҖ” posiciГіn en ganancia:
      Si PnL > 20%: stop = precio_actual Г— 0.92 (-8% desde precio actual)
      Si PnL > 40%: stop = precio_actual Г— 0.95 (-5% desde precio actual)
    """
    # в”Җв”Җ Determinar tipo de stop в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _es_tardio   = score_entrada > 55 or prob_entrada > 50
    _es_earnings = tenia_earnings
    _stop_estricto = _es_tardio or _es_earnings

    # в”Җв”Җ ETFs: reglas fijas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # v19 FIX: targets desde precio ACTUAL (pa), no desde precio de compra (pc)
    # Si pa no se pasa, usar pc como fallback
    _pa = pa if pa > 0 else pc
    _stop_activado = pa > 0 and pa < pc * 0.85  # posiciГіn en pГ©rdida significativa

    if tipo == "ETF_Indice":
        return {
            "stop_pct":   0,
            "stop_val":   0,
            "tipo_stop":  "Sin stop вҖ” mantener siempre",
            "etiqueta":   "рҹ“Ҡ ETF ГҚndice вҖ” nunca vender",
            "obj1": _pa*1.15, "obj2": _pa*1.25, "obj3": _pa*1.40,
            "razon": "Los ETF de Гӯndice no se venden por seГұal tГ©cnica",
            "stop_activado": False,
        }
    elif tipo == "ETF_Cripto":
        pct = -20.0
        _sv = pc*(1+pct/100)
        return {
            "stop_pct": pct, "stop_val": _sv,
            "tipo_stop": "Normal ETF Cripto",
            "etiqueta":  f"рҹӣ‘ Stop Cripto ({pct:.0f}%)",
            "obj1": _pa*1.20, "obj2": _pa*1.50, "obj3": _pa*2.00,
            "razon": "Alta volatilidad cripto вҖ” stop amplio",
            "stop_activado": pa > 0 and pa < _sv,
        }
    elif tipo == "ETF_Sectorial":
        pct = -12.0
        _sv = pc*(1+pct/100)
        return {
            "stop_pct": pct, "stop_val": _sv,
            "tipo_stop": "Normal ETF Sectorial",
            "etiqueta":  f"рҹӣ‘ Stop ETF ({pct:.0f}%)",
            "obj1": _pa*1.10, "obj2": _pa*1.25, "obj3": _pa*1.50,
            "razon": "ETF sectorial вҖ” stop estГЎndar -12%",
            "stop_activado": pa > 0 and pa < _sv,
        }

    # в”Җв”Җ Acciones: segГәn contexto в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    if _stop_estricto:
        pct = -5.0
        tipo_lbl = "Estricto"
        if _es_tardio:
            razon = f"SeГұal tardГӯa (Score {score_entrada:.0f} > 55 o Prob {prob_entrada:.0f}% > 50%)"
        else:
            razon = "Entrada con earnings prГіximos вҖ” stop ajustado"
        obj1 = _pa*1.08; obj2 = _pa*1.15; obj3 = _pa*1.25
    elif beta < 1.5:
        pct = -7.0
        tipo_lbl = "Normal beta bajo"
        razon = f"AcciГіn estable (Beta {beta:.1f})"
        obj1 = _pa*1.10; obj2 = _pa*1.20; obj3 = _pa*1.35
    elif beta < 2.5:
        pct = -10.0
        tipo_lbl = "Normal beta medio"
        razon = f"AcciГіn moderada (Beta {beta:.1f})"
        obj1 = _pa*1.12; obj2 = _pa*1.25; obj3 = _pa*1.45
    else:
        pct = -12.0
        tipo_lbl = "Normal beta alto"
        razon = f"AcciГіn volГЎtil (Beta {beta:.1f})"
        obj1 = _pa*1.15; obj2 = _pa*1.30; obj3 = _pa*1.60

    _sv_acc = round(pc * (1 + pct/100), 2)
    return {
        "stop_pct":  pct,
        "stop_val":  _sv_acc,
        "tipo_stop": tipo_lbl,
        "etiqueta":  f"рҹӣ‘ Stop {'вҡ пёҸ Estricto' if _stop_estricto else 'Normal'} ({pct:.0f}%)",
        "razon":     razon,
        "obj1": round(obj1,2), "obj2": round(obj2,2), "obj3": round(obj3,2),
        "stop_activado": pa > 0 and pa < _sv_acc,
    }

def render_pullback_badge(ticker: str, dd: float, rsi: float, ema_d: float,
                          dias_alcistas: int, vol_ratio: float,
                          G: str, R: str, A: str, C: str,
                          TXT_MUT: str,
                          tiene_posicion: bool = False,
                          pnl_pct: float = 0.0) -> str:
    """
    v19: Renderiza badge de tipo pullback para Watchlist, Swing y Posiciones.
    """
    pb = tipo_pullback(dd, rsi, ema_d, dias_alcistas, vol_ratio,
                       tiene_posicion, pnl_pct)
    if not pb:
        return ""

    return (
        f'<div style="background:{pb["bg"]};border-left:3px solid {pb["color"]};'
        f'border-radius:0 8px 8px 0;padding:8px 12px;margin-top:5px">'
        f'<div style="font-size:11px;font-weight:700;color:{pb["color"]};margin-bottom:3px">'
        f'{pb["emoji"]} {pb["nombre"]}</div>'
        f'<div style="font-size:10px;color:#374151;line-height:1.7">'
        f'{pb["descripcion"]}</div>'
        f'<div style="font-size:10px;font-weight:600;color:{pb["color"]};'
        f'margin-top:4px">вҶ’ {pb["accion"]}</div>'
        f'</div>'
    )


