def fetch_etf_data(ticker: str) -> dict:
    """Obtiene datos tГ©cnicos de un ETF desde yfinance."""
    try:
        import yfinance as yf
        import numpy as np
        tk  = yf.Ticker(ticker)
        hist = tk.history(period="6mo")
        if hist.empty or len(hist) < 20:
            return None
        close = hist["Close"].values
        vol   = hist["Volume"].values

        precio  = float(close[-1])
        pico    = float(close.max())
        dd      = round((precio - pico) / pico * 100, 1)

        # RSI 14
        delta  = hist["Close"].diff()
        gain   = delta.clip(lower=0).rolling(14).mean()
        loss   = (-delta.clip(upper=0)).rolling(14).mean()
        rsi    = round(float(100 - 100/(1 + gain.iloc[-1]/(loss.iloc[-1]+1e-9))), 1)

        # Tendencia 20d
        ema20  = float(hist["Close"].ewm(span=20).mean().iloc[-1])
        tend   = "вҶ‘" if precio > ema20 * 1.02 else "вҶ“" if precio < ema20 * 0.98 else "->"

        # YTD
        try:
            import datetime as _dt_ytd
            _eytd = _dt_ytd.date.today()
            _sytd = _eytd - _dt_ytd.timedelta(days=365)
            hist_ytd = tk.history(
                start=_sytd.strftime("%Y-%m-%d"),
                end=_eytd.strftime("%Y-%m-%d"))
            ytd_price = float(hist_ytd["Close"].iloc[0]) if not hist_ytd.empty else precio
            ytd_pct   = round((precio - ytd_price) / ytd_price * 100, 1)
        except:
            ytd_pct = 0.0

        # Volumen ratio
        avg_vol   = float(np.mean(vol[-20:]))
        vol_ratio = round(float(vol[-1]) / avg_vol * 100, 0) if avg_vol > 0 else 100

        # SeГұal de entrada
        if rsi < 35 and dd < -15:
            senal = "рҹҹў COMPRAR AHORA"
            senal_c = "16A34A"
        elif rsi < 50 and dd < -8:
            senal = "рҹҹЎ BUENA ENTRADA"
            senal_c = "D97706"
        elif rsi > 70:
            senal = "рҹ”ҙ ESPERAR - RSI alto"
            senal_c = "DC2626"
        elif dd > -3:
            senal = "вҡӘ EN MГҒXIMOS"
            senal_c = "64748B"
        else:
            senal = "рҹ”ө NEUTRAL"
            senal_c = "2563EB"

        return {
            "ticker":    ticker,
            "precio":    precio,
            "dd":        dd,
            "rsi":       rsi,
            "tend":      tend,
            "ytd":       ytd_pct,
            "vol_ratio": vol_ratio,
            "senal":     senal,
            "senal_c":   senal_c,
            "ema20":     ema20,
        }
    except Exception:
        return None


def calcular_estrategia(capital: float, plazo: str, perfil: str,
                         etf_data: dict) -> dict:
    """
    Calcula distribuciГіn Гіptima de capital en ETFs
    basada en indicadores actuales + perfil + plazo.
    """
    # Pesos base por perfil y plazo
    if perfil == "Moderado":
        if plazo == "Corto (6-12m)":
            base = {"Parking":0.50, "Indice":0.30, "Sectorial":0.10, "Cripto":0.10}
        elif plazo == "Mediano (2-5a)":
            base = {"Parking":0.20, "Indice":0.50, "Sectorial":0.20, "Cripto":0.10}
        else:  # Largo
            base = {"Parking":0.05, "Indice":0.55, "Sectorial":0.25, "Cripto":0.15}
    elif perfil == "Agresivo":
        if plazo == "Corto (6-12m)":
            base = {"Parking":0.20, "Indice":0.40, "Sectorial":0.25, "Cripto":0.15}
        elif plazo == "Mediano (2-5a)":
            base = {"Parking":0.05, "Indice":0.45, "Sectorial":0.30, "Cripto":0.20}
        else:
            base = {"Parking":0.00, "Indice":0.40, "Sectorial":0.35, "Cripto":0.25}
    else:  # Conservador
        if plazo == "Corto (6-12m)":
            base = {"Parking":0.70, "Indice":0.20, "Sectorial":0.10, "Cripto":0.00}
        elif plazo == "Mediano (2-5a)":
            base = {"Parking":0.40, "Indice":0.40, "Sectorial":0.15, "Cripto":0.05}
        else:
            base = {"Parking":0.20, "Indice":0.50, "Sectorial":0.25, "Cripto":0.05}

    # Ajustar por seГұales tГ©cnicas - sobreponderar ETFs en zona de compra
    allocations = []
    for tk, meta in ETF_UNIVERSE.items():
        d = etf_data.get(tk)
        if d is None:
            continue
        cat = meta["categoria"]
        peso_base = base.get(cat, 0)

        # Ajuste por RSI y DD
        if d["rsi"] < 40 and d["dd"] < -15:
            ajuste = 1.3   # sobreponderar
        elif d["rsi"] > 70:
            ajuste = 0.6   # subponderar
        elif d["dd"] > -3:
            ajuste = 0.8   # en mГЎximos, esperar
        else:
            ajuste = 1.0

        peso_ajustado = peso_base * ajuste
        monto         = round(capital * peso_ajustado, 0)

        allocations.append({
            "ticker":   tk,
            "nombre":   meta["nombre"],
            "categoria":cat,
            "riesgo":   meta["riesgo"],
            "rend_hist":meta["rend_hist"],
            "peso":     round(peso_ajustado * 100, 1),
            "monto":    monto,
            "rsi":      d["rsi"],
            "dd":       d["dd"],
            "senal":    d["senal"],
            "senal_c":  d["senal_c"],
            "tend":     d["tend"],
            "ytd":      d["ytd"],
            "precio":   d["precio"],
        })

    # Normalizar a 100%
    total_peso = sum(a["peso"] for a in allocations)
    if total_peso > 0:
        for a in allocations:
            a["peso"]  = round(a["peso"] / total_peso * 100, 1)
            a["monto"] = round(capital * a["peso"] / 100, 0)

    # DCA - dividir en meses segГәn plazo
    meses_dca = {"Corto (6-12m)": 3, "Mediano (2-5a)": 4, "Largo (5-10a)": 6}
    n_meses   = meses_dca.get(plazo, 4)
    monto_mes = round(capital / n_meses, 0)

    # ProyecciГіn
    rend_ponderado = sum(
        (a["monto"] / capital) * ETF_UNIVERSE[a["ticker"]]["rend_hist"]
        for a in allocations if capital > 0
    )
    aГұos = {"Corto (6-12m)": 1, "Mediano (2-5a)": 5, "Largo (5-10a)": 10}
    n_aГұos = aГұos.get(plazo, 5)
    proy_base = round(capital * (1 + rend_ponderado/100) ** n_aГұos, 0)
    proy_opt  = round(capital * (1 + (rend_ponderado+3)/100) ** n_aГұos, 0)
    proy_pes  = round(capital * (1 + max(rend_ponderado-4, 2)/100) ** n_aГұos, 0)

    return {
        "allocations":      sorted(allocations, key=lambda x: -x["monto"]),
        "n_meses":          n_meses,
        "monto_mes":        monto_mes,
        "rend_ponderado":   round(rend_ponderado, 1),
        "proy_base":        proy_base,
        "proy_opt":         proy_opt,
        "proy_pes":         proy_pes,
        "n_aГұos":           n_aГұos,
    }


def _ascii(x) -> str:
    """Convierte cualquier valor a string ASCII compatible con Excel Chile (latin-1)."""
    if not isinstance(x, str):
        x = str(x)
    _MAP = {
        "\u2014":"-", "\u2013":"-", "\u2012":"-",
        "\u2019":"'", "\u2018":"'",
        "\u201c":'"', "\u201d":'"',
        "\u2192":"->","\u2190":"<-","\u2191":"^","\u2193":"v",
        "\u00f1":"n", "\u00d1":"N",
        "\u00e9":"e", "\u00e1":"a", "\u00ed":"i",
        "\u00f3":"o", "\u00fa":"u", "\u00fc":"u",
        "\u00c9":"E", "\u00c1":"A", "\u00cd":"I",
        "\u00d3":"O", "\u00da":"U",
        "\u00bf":"?", "\u00a1":"!",
        "\U0001f525":"FUERTE", "\u26a1":"VALIDA",
        "\U0001f4e1":"M1", "\u2705":"OK",
        "\u26a0":    "ALERTA",
        "\U0001f6d1":"STOP",
        "\U0001f480":"MUERTA",
        "\U0001f504":"TRAILING",
        "\U0001f4b0":"", "\U0001f4ca":"",
        "\U0001f4c8":"", "\U0001f4c9":"",
        "-":"-", "-":"-", "->":"->", "вҶҗ":"<-",
        "Гұ":"n", "Г‘":"N",
        "Г©":"e", "ГЎ":"a", "Гӯ":"i", "Гі":"o", "Гә":"u",
        "Гү":"E", "ГҒ":"A", "ГҚ":"I", "Г“":"O", "Гҡ":"U",
        "Гј":"u", "ГҜ":"i",
    }
    for k, v in _MAP.items():
        x = x.replace(k, v)
    result = ""
    for ch in x:
        try:
            ch.encode("latin-1")
            result += ch
        except UnicodeEncodeError:
            result += "?"
    return result.strip()


def df_to_csv_chile(df: pd.DataFrame) -> str:
    """Exporta DataFrame en formato CSV Chile: separador ; y decimales con coma"""
    return df.to_csv(index=False, sep=";", decimal=",", encoding="utf-8-sig")


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  PROB NBIS v12 - Probabilidad real basada en patrГіn NBIS
#  NBIS referencia: RSI~38, Vol 280%, DD -55%, 3 dГӯas alcistas
#  momentum +27%, MACD positivo, catalizador earnings
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
NBIS_REF = {
    "rsi":       38.0,
    "vol":       280.0,
    "dd":        -55.0,
    "dias_alc":  3,
    "momentum":  27.0,
    "tiene_cat": True,
}

def calcular_prob_nbis(rsi: float, vol_ratio: float, dd: float,
                        dias_alcistas: int, momentum_3d: float,
                        tiene_catalizador: bool) -> float:
    """
    Probabilidad 0-100% de que la acciГіn repita el patrГіn NBIS.
    Compara condiciones actuales con el patrГіn NBIS de referencia.
    NO es similitud exacta - es quГ© tan cerca estГЎ de las condiciones
    que hicieron que NBIS funcionara.
    """
    score = 0.0

    # RSI (25 pts) - NBIS entrГі con RSI ~38
    if rsi <= 35:
        score += 25
    elif rsi <= 42:
        score += 22
    elif rsi <= 50:
        score += 15
    elif rsi <= 60:
        score += 8
    else:
        score += 0

    # Volumen (25 pts) - NBIS tenГӯa 280%
    if vol_ratio >= 250:
        score += 25
    elif vol_ratio >= 150:
        score += 20
    elif vol_ratio >= 100:
        score += 12
    elif vol_ratio >= 60:
        score += 6
    else:
        score += 0

    # DD (20 pts) - NBIS cayГі -55%, buscamos -20% a -50%
    if -50 <= dd <= -20:
        score += 20
    elif -60 <= dd <= -15:
        score += 15
    elif -70 <= dd <= -10:
        score += 8
    else:
        score += 0

    # DГӯas alcistas (15 pts) - NBIS tuvo 3 dГӯas
    if dias_alcistas >= 3:
        score += 15
    elif dias_alcistas == 2:
        score += 10
    elif dias_alcistas == 1:
        score += 5
    else:
        score += 0

    # Momentum 3d (10 pts) - NBIS tenГӯa +27% en 3 dГӯas
    if momentum_3d >= 15:
        score += 10
    elif momentum_3d >= 8:
        score += 8
    elif momentum_3d >= 4:
        score += 5
    elif momentum_3d >= 0:
        score += 2
    else:
        score += 0

    # Catalizador (5 pts)
    if tiene_catalizador:
        score += 5

    return round(score, 1)


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  NUEVA LГ“GICA M1/M2/M3 v12
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
def clasificar_etapa_v12(rsi: float, vol_ratio: float, prob_nbis: float,
                          dias_alcistas: int, momentum_3d: float,
                          score_rebote: int, dd: float = 0.0,
                          cat_fecha: str = "-") -> dict:
    """
    LГіgica de escalamiento v15 - incluye earnings como modificador de fase:

    Sin earnings / earnings lejanos (>30d):
      M1: RSI 40-60  - DD <= -8%
      M2: RSI 30-45  - Vol >= 50%  - Mom >= 1%  - 3dвҶ‘
      M3: RSI <= 42   - Vol >= 50%  - Mom >= 3%  - 3dвҶ‘

    Con earnings prГіximos (zona NBIS):
      7-15d: M2 -> M3 (zona Гіptima - catalizador activo)
      15-30d: M1 -> M2 (zona vГЎlida - da convicciГіn)
      3-6d:  badge вҡ пёҸ  sin ascenso (tarde para entrar)
      1-2d:  BLOQUEO  (riesgo binario)
      Post-earnings caГӯda >8%: M1 especial (setup mГЎs limpio)
    """
    import datetime as _dt
    # Calcular dГӯas para earnings
    _dias_cat = 999
    _tiene_cat = False
    if cat_fecha and cat_fecha not in ("-","","nan"):
        try:
            _fc = _dt.date.fromisoformat(str(cat_fecha)[:10])
            _dias_cat = (_fc - _dt.date.today()).days
            _tiene_cat = _dias_cat >= 0
        except Exception:
            pass
    # в•җв•җ FASES BASE (sin earnings) в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

    # M3 base - seГұal completa
    _es_m3 = (rsi <= 42 and momentum_3d >= 3 and dias_alcistas >= 3
              and prob_nbis >= 35 and vol_ratio >= 50 and dd <= -8)

    # M2 base - preparar orden
    _es_m2 = (30 <= rsi <= 45 and vol_ratio >= 50
              and prob_nbis >= 40 and dias_alcistas >= 3
              and momentum_3d >= 1.0 and dd <= -8)

    # M1 base - radar
    _es_m1 = (35 <= rsi <= 60 and prob_nbis >= 35 and dd <= -8)

    # в•җв•җ MODIFICADORES DE EARNINGS (v15) в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # AMD caso real: earning ayer -> +10% hoy. Con este bloque hubiera sido M3.
    _earn_label = ""
    _earn_color = ""

    if _tiene_cat:
        if _dias_cat <= 2:
            # рҹҡ« BLOQUEO total - earnings en 0-2 dГӯas
            return {"etapa": "ESPERAR", "label": "рҹҡ« ESPERAR EARNINGS",
                    "color": "DC2626", "bg": "FEF2F2",
                    "accion": f"Earnings en {_dias_cat}d - riesgo binario. NO entrar. Esperar resultado.",
                    "earn_badge": f"рҹҡ« Earnings en {_dias_cat}d", "earn_dias": _dias_cat}

        elif _dias_cat <= 6:
            # вҡ пёҸ CAUCIГ“N - no ascender pero badge de advertencia
            _earn_label = f"вҡ пёҸ Earnings en {_dias_cat}d - Tarde para entrar"
            _earn_color = "D97706"

        elif _dias_cat <= 15:
            # рҹҺҜ ZONA Г“PTIMA - ascenso de fase
            # M2 -> M3: catalizador confirmado (caso NBIS real)
            if _es_m2 and not _es_m3:
                _es_m3 = True
                _earn_label = f"рҹҺҜ Earnings {_dias_cat}d - M2->M3 catalizador activo"
                _earn_color = "16A34A"
            # M1 -> M2: convicciГіn extra
            elif _es_m1 and not _es_m2 and not _es_m3:
                _es_m2 = True
                _earn_label = f"рҹҺҜ Earnings {_dias_cat}d - M1->M2 convicciГіn extra"
                _earn_color = "0891B2"
            else:
                _earn_label = f"рҹҺҜ Earnings {_dias_cat}d - zona Гіptima"
                _earn_color = "16A34A"

        elif _dias_cat <= 30:
            # вҡЎ ZONA VГҒLIDA - M1 puede subir a M2
            if _es_m1 and not _es_m2 and not _es_m3:
                _es_m2 = True
                _earn_label = f"вҡЎ Earnings {_dias_cat}d - M1->M2"
                _earn_color = "0891B2"
            else:
                _earn_label = f"рҹ“… Earnings {_dias_cat}d"
                _earn_color = "2563EB"
        else:
            _earn_label = f"рҹ“… Earnings {_dias_cat}d"
            _earn_color = "64748B"

    # в•җв•җ RETORNO SEGГҡN FASE FINAL в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    if _es_m3:
        _accion = "Ejecutar en apertura - seГұal completa"
        if _earn_label:
            _accion = f"{_earn_label}  - {_accion}"
        return {"etapa": "M3", "label": "рҹ”Ҙ ENTRAR HOY",
                "color": "16A34A", "bg": "F0FDF4",
                "accion": _accion,
                "earn_badge": _earn_label, "earn_color": _earn_color,
                "earn_dias": _dias_cat}

    if _es_m2:
        _accion = "Preparar orden  - Definir stop y targets"
        if _earn_label:
            _accion = f"{_earn_label}  - {_accion}"
        return {"etapa": "M2", "label": "вҡЎ EN FORMACIГ“N M2",
                "color": "D97706", "bg": "FFFBEB",
                "accion": _accion,
                "earn_badge": _earn_label, "earn_color": _earn_color,
                "earn_dias": _dias_cat}

    if _es_m1:
        _accion = "En el radar  - NO entrar aГәn"
        if _earn_label:
            _accion = f"{_earn_label}  - {_accion}"
        return {"etapa": "M1", "label": "рҹ“Ў DETECTADA",
                "color": "2563EB", "bg": "EFF6FF",
                "accion": _accion,
                "earn_badge": _earn_label, "earn_color": _earn_color,
                "earn_dias": _dias_cat}

    # в”Җв”Җ v15: MODIFICADORES POR EARNINGS в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Se aplican DESPUГүS de la clasificaciГіn base para ascender/bloquear
    if _tiene_cat:
        if _dias_cat <= 2:
            # рҹҡ« BLOQUEO - earnings maГұana/pasado maГұana
            return {"etapa": "ESPERAR", "label": "рҹҡ« ESPERAR EARNINGS",
                    "color": "DC2626", "bg": "FEF2F2",
                    "accion": f"Earnings en {_dias_cat}d - riesgo binario. NO entrar hasta ver resultado.",
                    "earn_badge": f"рҹҡ« Earnings en {_dias_cat}d", "earn_dias": _dias_cat}

        elif _dias_cat <= 6:
            # вҡ пёҸ CAUCIГ“N - tarde para entrar, no cambia fase pero aГұade badge
            pass  # fase calculada arriba se devuelve con badge abajo

        elif _dias_cat <= 15:
            # рҹҺҜ ZONA Г“PTIMA - ascenso de fase
            pass  # ascenso ya aplicado en la lГіgica de fases abajo

        elif _dias_cat <= 30:
            # вҡЎ ZONA VГҒLIDA - M1 puede subir a M2
            pass

    # Sin etapa
    return {"etapa": "-", "label": "рҹ”ө OBSERVAR",
            "color": "64748B", "bg": "F8FAFC",
            "accion": "Sin seГұal"}


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  SEГ‘ALES DE SALIDA v12
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
def calcular_seГұales_salida_v12(pnl_pct: float, precio_compra: float,
                                  precio_actual: float, precio_max: float,
                                  dias_posicion: int, estrategia: str,
                                  tipo: str) -> dict:
    """
    Nueva lГіgica de salida v12:
    T1 +8%:  vender 40% -> mover stop a breakeven
    T2 +12%: vender 40% -> 20% queda con trailing stop
    Trailing: stop = precio_max x 0.95 (-5% desde mГЎximo)
    Muerta:   >5 dГӯas en Вұ1% -> seГұal "Salir y reasignar"
    Stop:     -7% automГЎtico sin discreciГіn
    """
    if estrategia == "Largo_Plazo":
        return {"seГұal": "рҹ“Ҡ Largo plazo", "accion": "Mantener sin stop",
                "urgencia": "-", "tramos": [], "color": "2563EB"}

    seГұales = []
    urgencia = "-"
    color = "64748B"

    # Stop diferenciado por tipo вҖ” v18 fix: ETF_Cripto necesita -20% mГӯnimo
    # ETHA puede caer 15% en un dГӯa вҖ” stop de -10% serГӯa seГұal falsa
    if tipo == "Accion":
        stop_pct = -7.0
        stop_label = "Stop acciГіn (-7%)"
    elif tipo == "ETF_Indice":
        stop_pct = -12.0
        stop_label = "Stop ETF ГҚndice (-12%)"
    elif tipo == "ETF_Cripto":
        stop_pct = -20.0
        stop_label = "Stop ETF Cripto (-20%) вҖ” volatilidad normal en crypto"
    elif tipo == "ETF_Sectorial":
        stop_pct = -12.0
        stop_label = "Stop ETF Sectorial (-12%)"
    elif tipo == "ETF_LatAm":
        stop_pct = -12.0
        stop_label = "Stop ETF LatAm (-12%)"
    else:
        stop_pct = -10.0
        stop_label = "Stop (-10%)"

    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # LГ“GICA ETF вҖ” completamente distinta a acciones
    # Los ETF no se venden por seГұales tГ©cnicas individuales
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

    if tipo == "ETF_Indice":
        # VOO, SPY, QQQ вҖ” acumulaciГіn de largo plazo
        # NUNCA vender por seГұal tГ©cnica вҖ” solo rebalanceo o necesidad de capital
        if pnl_pct <= -12.0:
            return {
                "seГұal": "вҡ пёҸ CorrecciГіn ETF ГҚndice (-12%)",
                "accion": "Considerar AGREGAR posiciГіn вҖ” el S&P500 siempre se recupera histГіricamente. Solo salir si necesitas el capital.",
                "urgencia": "REVISAR",
                "tramos": [(0,"MANTENER"),(100,"CONSIDERAR AGREGAR")],
                "color": "2563EB",
            }
        if pnl_pct >= 25.0:
            return {
                "seГұal": "вң… ETF ГҚndice +25% вҖ” Rebalanceo opcional",
                "accion": f"Ganancia +{pnl_pct:.0f}%. Puedes vender 20-30% para rebalancear portafolio. Mantener el resto indefinidamente.",
                "urgencia": "OPCIONAL",
                "tramos": [(25,"REBALANCEO OPCIONAL"),(75,"MANTENER LP")],
                "color": "16A34A",
            }
        if pnl_pct >= 15.0:
            return {
                "seГұal": f"рҹ“Ҳ ETF ГҚndice +{pnl_pct:.0f}% вҖ” en tendencia",
                "accion": "Mantener. ETF Гӯndice no se vende en tendencia alcista. Stop mental en -12% desde precio de compra.",
                "urgencia": "MANTENER",
                "tramos": [(100,"MANTENER LP")],
                "color": "16A34A",
            }
        if pnl_pct >= 0:
            return {
                "seГұal": f"рҹ“Ҡ ETF ГҚndice +{pnl_pct:.0f}%",
                "accion": "Mantener. Horizonte largo plazo. Agregar en correcciones de -5% o mГЎs.",
                "urgencia": "MANTENER",
                "tramos": [(100,"MANTENER LP")],
                "color": "2563EB",
            }
        # En pГ©rdida вҖ” oportunidad de agregar
        return {
            "seГұal": f"вҡЎ ETF ГҚndice {pnl_pct:.0f}% вҖ” oportunidad",
            "accion": f"PГ©rdida temporal {pnl_pct:.0f}%. Considera agregar mГЎs VOO/SPY вҖ” las correcciones son oportunidades de acumulaciГіn. Stop mental -12%.",
            "urgencia": "REVISAR",
            "tramos": [(100,"MANTENER / AGREGAR")],
            "color": "D97706",
        }

    elif tipo == "ETF_Sectorial":
        # TAN, XBI вҖ” sector rotation, horizontes medios
        # Stop -12%, targets +20/40/60%
        if pnl_pct <= -12.0:
            return {
                "seГұal": "рҹӣ‘ Stop ETF Sectorial (-12%)",
                "accion": f"Stop activado en -12%. El sector cambiГі de tendencia. Salir y reasignar a sector mГЎs fuerte.",
                "urgencia": "HOY",
                "tramos": [(100,"VENDER TODO")],
                "color": "DC2626",
            }
        if pnl_pct >= 60.0:
            return {
                "seГұal": f"рҹҡҖ ETF Sectorial +{pnl_pct:.0f}% вҖ” T3 runner",
                "accion": "Objetivo T3 alcanzado. Vender 50%, mantener 50% con stop en +40% (breakeven alto).",
                "urgencia": "HOY",
                "tramos": [(50,"VENDER 50%"),(50,"RUNNER")],
                "color": "16A34A",
            }
        if pnl_pct >= 40.0:
            return {
                "seГұal": f"вң… ETF Sectorial +{pnl_pct:.0f}% вҖ” T2",
                "accion": "T2 alcanzado (+40%). Vender 40%. Mantener 60% con stop en +20%.",
                "urgencia": "ESTA SEMANA",
                "tramos": [(40,"VENDER 40%"),(60,"MANTENER")],
                "color": "16A34A",
            }
        if pnl_pct >= 20.0:
            return {
                "seГұal": f"вң… ETF Sectorial +{pnl_pct:.0f}% вҖ” T1",
                "accion": "T1 alcanzado (+20%). Vender 30%. Mover stop a breakeven (+0%). Dejar correr al T2 (+40%).",
                "urgencia": "ESTA SEMANA",
                "tramos": [(30,"VENDER 30%"),(70,"MANTENER")],
                "color": "16A34A",
            }
        if pnl_pct >= 0:
            return {
                "seГұal": f"рҹ“Ҳ ETF Sectorial +{pnl_pct:.0f}%",
                "accion": f"En camino al T1 (+20%). Mantener. Stop en -12%.",
                "urgencia": "MANTENER",
                "tramos": [(100,"MANTENER")],
                "color": "2563EB",
            }
        falta_stop = pnl_pct - (-12.0)
        return {
            "seГұal": f"вҡ пёҸ ETF Sectorial {pnl_pct:.0f}%",
            "accion": f"PГ©rdida {pnl_pct:.0f}%. Stop a {abs(falta_stop):.1f}% de activarse (-12%). Revisar si el sector sigue vГЎlido.",
            "urgencia": "VIGILAR",
            "tramos": [(100,"MANTENER")],
            "color": "D97706",
        }

    elif tipo == "ETF_Cripto":
        # IBIT, ETHA вҖ” alta volatilidad, ciclos crypto
        # Stop -20%, targets +30/60/100%
        if pnl_pct <= -20.0:
            return {
                "seГұal": "рҹӣ‘ Stop ETF Cripto (-20%)",
                "accion": "Stop activado en -20%. Salir del ciclo bajista crypto. Reentrar cuando BTC/ETH retome tendencia alcista.",
                "urgencia": "HOY",
                "tramos": [(100,"VENDER TODO")],
                "color": "DC2626",
            }
        if pnl_pct >= 100.0:
            return {
                "seГұal": f"рҹҡҖ ETF Cripto +{pnl_pct:.0f}% вҖ” T3 excepcional",
                "accion": "Objetivo mГЎximo superado. Vender 60%, mantener 40% como runner con stop en +60%.",
                "urgencia": "ESTA SEMANA",
                "tramos": [(60,"VENDER 60%"),(40,"RUNNER")],
                "color": "16A34A",
            }
        if pnl_pct >= 60.0:
            return {
                "seГұal": f"вң… ETF Cripto +{pnl_pct:.0f}% вҖ” T2",
                "accion": "T2 alcanzado (+60%). Vender 40%. Mantener 60% con stop en +30%. Ciclo crypto puede continuar.",
                "urgencia": "ESTA SEMANA",
                "tramos": [(40,"VENDER 40%"),(60,"MANTENER")],
                "color": "16A34A",
            }
        if pnl_pct >= 30.0:
            return {
                "seГұal": f"вң… ETF Cripto +{pnl_pct:.0f}% вҖ” T1",
                "accion": "T1 alcanzado (+30%). Vender 30%. Stop a breakeven (+0%). Dejar correr al T2 (+60%).",
                "urgencia": "ESTA SEMANA",
                "tramos": [(30,"VENDER 30%"),(70,"MANTENER")],
                "color": "16A34A",
            }
        if pnl_pct >= 0:
            falta = 30.0 - pnl_pct
            return {
                "seГұal": f"рҹ“Ҳ ETF Cripto +{pnl_pct:.0f}%",
                "accion": f"En camino al T1 (+30%). Faltan +{falta:.0f}%. Stop en -20%. Ciclos crypto son lentos вҖ” paciencia.",
                "urgencia": "MANTENER",
                "tramos": [(100,"MANTENER")],
                "color": "2563EB",
            }
        falta_stop = pnl_pct - (-20.0)
        return {
            "seГұal": f"вҡ пёҸ ETF Cripto {pnl_pct:.0f}%",
            "accion": f"PГ©rdida {pnl_pct:.0f}%. Stop a {abs(falta_stop):.1f}% de activarse (-20%). Crypto puede caer mГЎs вҖ” stop es amplio por diseГұo.",
            "urgencia": "VIGILAR",
            "tramos": [(100,"MANTENER")],
            "color": "D97706",
        }

    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
    # LГ“GICA ACCIONES вҖ” T1/T2/Trailing original
    # в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

    stop_pct = -7.0
    if pnl_pct <= stop_pct:
        return {
            "seГұal": f"рҹӣ‘ STOP ACTIVADO ({stop_pct}%)",
            "accion": f"VENDER TODO AHORA вҖ” {stop_label}",
            "urgencia": "AHORA",
            "tramos": [(100, "VENDER TODO")],
            "color": "DC2626",
            "stop_pct": stop_pct,
        }

    # PosiciГіn muerta (>5 dГӯas en Вұ1%)
    if dias_posicion >= 5 and abs(pnl_pct) <= 1.0:
        return {
            "seГұal": "рҹ’Җ PosiciГіn muerta",
            "accion": "Salir y reasignar capital a seГұal M3 activa",
            "urgencia": "HOY",
            "tramos": [(100, "SALIR")],
            "color": "7C3AED",
        }

    # Trailing stop despuГ©s de T2
    if pnl_pct >= 12.0 and precio_max > precio_compra:
        trailing_stop = precio_max * 0.95
        trailing_pct  = (trailing_stop - precio_compra) / precio_compra * 100
        if precio_actual <= trailing_stop:
            return {
                "seГұal": "рҹ”„ Trailing stop activado",
                "accion": f"Vender 20% residual - precio cayГі bajo trailing ${trailing_stop:.2f}",
                "urgencia": "AHORA",
                "tramos": [(20, "VENDER 20% RESIDUAL")],
                "color": "D97706",
                "trailing_stop": trailing_stop,
            }
        seГұales.append(f"Trailing stop en ${trailing_stop:.2f} (+{trailing_pct:.1f}%)")
        color = "16A34A"
        urgencia = "Vigilar"

    # T2 +12% -> vender 40% - SIEMPRE, catalizador no bloquea
    if pnl_pct >= 12.0:
        return {
            "seГұal": "вң… T2 +12% - Vender 40%",
            "accion": "Vender 40% adicional  - 20% queda con trailing stop -5%",
            "urgencia": "HOY",
            "tramos": [(40, "VENDER 40%"), (40, "YA VENDIDO T1"), (20, "RUNNER + TRAILING")],
            "color": "16A34A",
        }

    # T1 +8% -> vender 40% - SIEMPRE, catalizador no bloquea
    if pnl_pct >= 7.9:  # usar 7.9 para capturar exactamente +8%
        return {
            "seГұal": "вң… T1 +8% - Vender 40%",
            "accion": "Vender 40%  - Stop remanente a breakeven",
            "urgencia": "HOY",
            "tramos": [(40, "VENDER 40%"), (60, "MANTENER + STOP BE")],
            "color": "16A34A",
        }

    # En camino a T1
    if pnl_pct > 0:
        falta_t1 = 8.0 - pnl_pct
        _stop_precio = round(precio_compra * (1 + stop_pct/100), 2)
        return {
            "seГұal": f"рҹ“Ҳ En camino T1 вҖ” faltan +{falta_t1:.1f}%",
            "accion": (f"MANTENER В· Stop duro ${_stop_precio:.2f} ({stop_pct}%) В· "
                      f"Objetivo T1 +8% В· T2 +12%"),
            "urgencia": "Mantener",
            "tramos": [(100, "MANTENER")],
            "color": "2563EB",
            "stop_precio": _stop_precio,
        }

    # En pГ©rdida pero sobre el stop вҖ” enriquecer con precio de stop y contexto
    falta_stop  = pnl_pct - stop_pct
    _stop_precio = round(precio_compra * (1 + stop_pct/100), 2)
    _pa_actual   = precio_actual if precio_actual > 0 else precio_compra * (1 + pnl_pct/100)

    # Intentar obtener targets de analistas para enriquecer el contexto
    _targets_msg = ""
    try:
        _pt = get_price_targets(ticker)
        if _pt.get("ok") and _pt.get("target_mean", 0) > 0:
            _up_mean = round((_pt["target_mean"] - _pa_actual) / _pa_actual * 100, 1)
            _na      = _pt.get("n_analysts", 0)
            if _up_mean > 10:
                _targets_msg = (f" В· Analistas: target ${_pt['target_mean']:.0f} "
                               f"(+{_up_mean:.0f}% upside В· {_na} analistas)")
    except Exception:
        pass

    return {
        "seГұal": f"вҡ пёҸ En pГ©rdida {pnl_pct:+.1f}% В· stop en {stop_pct}%",
        "accion": (f"MANTENER В· Stop duro ${_stop_precio:.2f} вҖ” "
                  f"a {abs(falta_stop):.1f}% de activarse"
                  f"{_targets_msg}"),
        "urgencia": "Vigilar",
        "tramos": [(100, "MANTENER")],
        "color": "D97706",
        "stop_precio": _stop_precio,
        "falta_stop": round(falta_stop, 1),
    }


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  SCORE DE REBOTE v11 - Reemplaza Prob NBIS + Sim NBIS
#  Basado en condiciones del patrГіn, no en comparaciГіn exacta
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
def calcular_score_rebote(dd: float, rsi: float, vol_ratio: float,
                           dias_alcistas: int, momentum_3d: float,
                           tiene_catalizador: bool, dias_para_cat: int,
                           beta: float) -> dict:
    """
    Score de rebote 0-100 basado en 4 componentes:
    30% DD (correcciГіn profunda)
    25% RSI girando desde zona baja
    25% Volumen confirmando
    20% Catalizador prГіximo
    """
    # в”Җв”Җ Componente 1: DD (30 pts) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Buscamos correcciГіn real pero no destrucciГіn
    if dd <= -40:
        pts_dd = 25    # muy profundo - posible destrucciГіn
    elif dd <= -30:
        pts_dd = 30    # ideal - correcciГіn severa
    elif dd <= -20:
        pts_dd = 28    # muy bueno
    elif dd <= -15:
        pts_dd = 22    # bueno
    elif dd <= -10:
        pts_dd = 15    # moderado
    elif dd <= -5:
        pts_dd = 8     # leve
    else:
        pts_dd = 0     # en mГЎximos - no hay correcciГіn

    # в”Җв”Җ Componente 2: RSI girando (25 pts) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # RSI bajo + subiendo = zona ideal de entrada
    if rsi <= 30:
        pts_rsi = 25   # sobreventa extrema
    elif rsi <= 38:
        pts_rsi = 23   # sobreventa clara
    elif rsi <= 45:
        pts_rsi = 18   # zona baja - buena entrada
    elif rsi <= 55:
        pts_rsi = 12   # zona media - aceptable
    elif rsi <= 65:
        pts_rsi = 5    # zona alta - precauciГіn
    else:
        pts_rsi = 0    # sobrecomprado - no entrar

    # Bonus si momentum positivo (RSI girando hacia arriba)
    if momentum_3d > 0 and dias_alcistas >= 2:
        pts_rsi = min(pts_rsi + 5, 25)

    # в”Җв”Җ Componente 3: Volumen (25 pts) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Volumen alto confirma que el movimiento es real
    if vol_ratio >= 300:
        pts_vol = 25   # excepcional - institucional
    elif vol_ratio >= 200:
        pts_vol = 22   # muy alto
    elif vol_ratio >= 150:
        pts_vol = 18   # alto - buena seГұal
    elif vol_ratio >= 100:
        pts_vol = 12   # normal
    elif vol_ratio >= 70:
        pts_vol = 6    # bajo
    else:
        pts_vol = 0    # muy bajo - seГұal dГ©bil

    # в”Җв”Җ Componente 4: Catalizador (20 pts) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    if tiene_catalizador and dias_para_cat <= 7:
        pts_cat = 20   # earnings en menos de 1 semana
    elif tiene_catalizador and dias_para_cat <= 15:
        pts_cat = 16   # earnings en 2 semanas
    elif tiene_catalizador and dias_para_cat <= 30:
        pts_cat = 10   # earnings en el mes
    elif tiene_catalizador:
        pts_cat = 5    # earnings lejanos
    else:
        pts_cat = 0    # sin catalizador identificado

    # в”Җв”Җ Score total в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    score_total = pts_dd + pts_rsi + pts_vol + pts_cat

    # PenalizaciГіn por Beta muy alto sin volumen
    if beta > 3.0 and vol_ratio < 100:
        score_total = max(score_total - 10, 0)

    # ClasificaciГіn
    if score_total >= 75:
        nivel = "рҹ”Ҙ FUERTE"
        color = "16A34A"
    elif score_total >= 60:
        nivel = "вҡЎ BUENO"
        color = "D97706"
    elif score_total >= 45:
        nivel = "рҹҹЎ MODERADO"
        color = "2563EB"
    else:
        nivel = "рҹ”ө DГүBIL"
        color = "64748B"

    return {
        "score":      score_total,
        "nivel":      nivel,
        "color":      color,
        "pts_dd":     pts_dd,
        "pts_rsi":    pts_rsi,
        "pts_vol":    pts_vol,
        "pts_cat":    pts_cat,
        "detalle":    f"DD:{pts_dd}/30  - RSI:{pts_rsi}/25  - Vol:{pts_vol}/25  - Cat:{pts_cat}/20",
    }


def calcular_atr(ticker: str, periodo: int = 14) -> float:
    """Calcula ATR (Average True Range) real de los Гәltimos N dГӯas."""
    try:
        import yfinance as yf, numpy as np
        import time as _tm_bd
        _tm_bd.sleep(0.05)
        hist = yf.Ticker(ticker).history(period="3mo")
        if hist.empty or len(hist) < periodo + 1:
            return 0.0
        high = hist["High"].values
        low  = hist["Low"].values
        close_prev = hist["Close"].values[:-1]
        high_c = high[1:]
        low_c  = low[1:]
        tr = np.maximum(high_c - low_c,
             np.maximum(abs(high_c - close_prev),
                        abs(low_c  - close_prev)))
        atr = float(np.mean(tr[-periodo:]))
        return round(atr, 4)
    except Exception:
        return 0.0


def sizing_por_atr(ticker: str, precio_actual: float,
                   capital_riesgo_usd: float = 500,
                   atr_mult: float = 1.5,
                   score: int = 50,
                   vix_val: float = 20) -> dict:
    """
    Sizing profesional basado en ATR - v16.
    FГіrmula: acciones = capital_riesgo / (ATR x atr_mult)

    Ejemplo NBIS: ATR=$8, riesgo=$500, mult=1.5
    -> stop = precio - (8x1.5) = precio - $12
    -> acciones = 500/12 = 41 acciones
    -> riesgo real = 41 x $12 = $492

    ParГЎmetros:
      capital_riesgo_usd: cuГЎnto estГЎs dispuesto a perder en este trade
      atr_mult: multiplicador del ATR para el stop (default 1.5)
      score: score del modelo (ajusta el sizing)
      vix_val: VIX actual (ajusta el sizing en pГЎnico)
    """
    atr = calcular_atr(ticker)

    # Si no hay ATR, usar % fijo del precio como fallback
    if atr <= 0:
        atr = precio_actual * 0.03  # 3% del precio = ATR estimado

    stop_distancia  = round(atr * atr_mult, 2)
    stop_precio     = round(precio_actual - stop_distancia, 2)
    stop_pct        = round(stop_distancia / precio_actual * 100, 1)

    # Cantidad de acciones
    acciones_raw    = capital_riesgo_usd / stop_distancia
    acciones        = max(1, int(acciones_raw))

    # Ajuste por score del modelo
    if score >= 75:
        score_mult = 1.0;   score_label = "SeГұal fuerte - 100%"
    elif score >= 60:
        score_mult = 0.75;  score_label = "SeГұal buena - 75%"
    elif score >= 45:
        score_mult = 0.50;  score_label = "SeГұal moderada - 50%"
    else:
        score_mult = 0.25;  score_label = "SeГұal dГ©bil - 25%"

    # Ajuste por VIX (pГЎnico = oportunidad = mГЎs tamaГұo)
    if vix_val >= 35:
        vix_mult = 1.20;  vix_label = "VIX pГЎnico -> +20%"
    elif vix_val >= 25:
        vix_mult = 1.10;  vix_label = "VIX miedo -> +10%"
    elif vix_val < 15:
        vix_mult = 0.80;  vix_label = "VIX complacencia -> -20%"
    else:
        vix_mult = 1.0;   vix_label = "VIX normal -> sin ajuste"

    acciones_final  = max(1, int(acciones * score_mult * vix_mult))
    capital_total   = round(acciones_final * precio_actual, 2)
    riesgo_real     = round(acciones_final * stop_distancia, 2)

    # Targets basados en ATR
    t1 = round(precio_actual + atr * 2, 2)   # T1: +2 ATR (~60% posiciГіn)
    t2 = round(precio_actual + atr * 4, 2)   # T2: +4 ATR (~30% posiciГіn)
    t3 = round(precio_actual + atr * 6, 2)   # T3: +6 ATR (runner 10%)

    return {
        "ticker":           ticker,
        "precio":           precio_actual,
        "atr":              round(atr, 2),
        "atr_mult":         atr_mult,
        "stop_distancia":   stop_distancia,
        "stop_precio":      stop_precio,
        "stop_pct":         stop_pct,
        "acciones":         acciones_final,
        "capital_total":    capital_total,
        "riesgo_real":      riesgo_real,
        "score_mult":       score_mult,
        "score_label":      score_label,
        "vix_mult":         vix_mult,
        "vix_label":        vix_label,
        "t1":               t1,
        "t2":               t2,
        "t3":               t3,
        "t1_pct":           round((t1/precio_actual-1)*100, 1),
        "t2_pct":           round((t2/precio_actual-1)*100, 1),
        "t3_pct":           round((t3/precio_actual-1)*100, 1),
        "formula":          f"{acciones_final} acc x ${stop_distancia:.2f} stop = ${riesgo_real:.0f} riesgo real",
        "detalle":          f"ATR ${atr:.2f} x {atr_mult} = stop ${stop_distancia:.2f} ({stop_pct}%)",
    }


def clasificar_sizing(score: int, vix: float) -> dict:
    """Legacy - se mantiene para compatibilidad. Usar sizing_por_atr() en v16."""
    return sizing_por_atr("", 100, score=score, vix_val=vix)


def generar_csv_posiciones_actualizado(posiciones_df: pd.DataFrame,
                                        resultados: list,
                                        nombre_archivo: str) -> bytes:
    """
    Genera CSV actualizado de posiciones aplicando salidas T1/T2.
    Si T1 se activГі: reduce cantidad en 40%
    Si T2 se activГі: reduce cantidad en 40% adicional
    Si Stop: elimina la posiciГіn
    Si Muerta: marca para revisiГіn
    """
    import datetime as _dt
    rows_nuevas = []

    for res in resultados:
        tk      = res.get("ticker","")
        pnl     = res.get("pnl_pct", 0)
        analisis= res.get("analisis_v12",{})
        urgencia= analisis.get("urgencia","-")
        seГұal   = analisis.get("seГұal","-")

        # Buscar en posiciones_df
        mask = posiciones_df["Ticker"].str.upper() == tk.upper()
        if not mask.any():
            continue
        row = posiciones_df[mask].iloc[0]
        qty_original = _parse_precio(row.get("Cantidad", 0))

        # Aplicar salidas
        if "STOP" in seГұal or urgencia == "AHORA" and "Trailing" not in seГұal:
            # Stop activado -> no incluir (posiciГіn cerrada)
            continue
        elif "T2 +12%" in seГұal:
            # T2: ya se vendiГі 40% en T1 + 40% en T2 -> queda 20%
            qty_nueva = round(qty_original * 0.20, 6)
            nota = "20% runner post-T2"
        elif "T1 +8%" in seГұal:
            # T1: se vendiГі 40% -> queda 60%
            qty_nueva = round(qty_original * 0.60, 6)
            nota = "60% post-T1  - stop en breakeven"
        elif "muerta" in seГұal.lower():
            # PosiciГіn muerta -> marcar pero mantener
            qty_nueva = qty_original
            nota = "вҡ пёҸ Revisar - posiciГіn muerta"
        else:
            qty_nueva = qty_original
            nota = ""

        nueva_fila = {
            "Ticker":        row["Ticker"],
            "Fecha":         row["Fecha"],
            "Precio_Compra": row["Precio_Compra"],
            "Cantidad":      qty_nueva,
            "Cat_Fecha":     row.get("Cat_Fecha","-"),
            "Tipo":          row.get("Tipo","Accion"),
            "Estrategia":    row.get("Estrategia","Swing"),
            "Fase_Origen":   row.get("Fase_Origen","-"),
            "Notas_Salida":  nota,
        }
        rows_nuevas.append(nueva_fila)

    if not rows_nuevas:
        return b""

    df_nuevo = pd.DataFrame(rows_nuevas)
    return df_nuevo.to_csv(index=False, sep=";", decimal=",",
                           encoding="utf-8-sig").encode("utf-8-sig")


def calcular_score_gestion(pnl_pct: float, dias_posicion: int,
                             precio_max: float, precio_actual: float,
                             precio_compra: float) -> dict:
    """
    Score de GESTIГ“N de posiciГіn abierta (diferente al Score de entrada)
    No usa RSI ni indicadores tГ©cnicos - usa PnL real
    0-100: mayor score = mantener mГЎs tiempo
    """
    score = 50  # neutral base

    # PnL actual
    if pnl_pct >= 12:
        score += 30
    elif pnl_pct >= 8:
        score += 20
    elif pnl_pct >= 4:
        score += 10
    elif pnl_pct >= 0:
        score += 0
    elif pnl_pct >= -4:
        score -= 15
    elif pnl_pct >= -7:
        score -= 30
    else:
        score -= 50

    # DГӯas en posiciГіn
    if dias_posicion > 8:
        score -= 20
    elif dias_posicion > 5:
        score -= 10

    # Distancia desde mГЎximo
    if precio_max > 0 and precio_compra > 0:
        caida_max = (precio_actual - precio_max) / precio_max * 100
        if caida_max < -10:
            score -= 15
        elif caida_max < -5:
            score -= 5

    score = max(0, min(100, score))

    if score >= 70:
        return {"score": score, "accion": "Mantener", "color": "16A34A"}
    elif score >= 50:
        return {"score": score, "accion": "Vigilar", "color": "D97706"}
    elif score >= 30:
        return {"score": score, "accion": "Preparar salida", "color": "F97316"}
    else:
        return {"score": score, "accion": "Salir", "color": "DC2626"}


@st.cache_data(ttl=300, show_spinner=False)
def scan_detectadas(rsi_min: float = 35, rsi_max: float = 60,
                    dd_min: float = -8, score_min: int = 15,
                    max_results: int = 100, universo: list = None) -> pd.DataFrame:
    """
    Scanner de Detectadas M1 usando yfinance directo.
    Busca acciones EN CORRECCIГ“N (aГәn bajando) con Prob NBIS >= 20%.
    M1: RSI 35-60  - DD <= -8%  - correcciГіn activa
    """
    import yfinance as yf
    candidatos = []
    _universo = universo if universo else SCAN_UNIVERSE

    try:
        for tk in _universo:
            try:
                _ETF_SKIP = {"XLE","XLI","XLY","XLC","XLB","XLP","XLRE","GLD",
                             "SLV","USO","UNG","JETS","HACK","BOTZ","ROBO",
                             "COPX","ARKG","ARKF","ARKQ","SOXX","IBB","ARKK"}
                if tk in _ETF_SKIP:
                    continue

                hist = yf.Ticker(tk).history(period="3mo")
                if hist.empty or len(hist) < 20:
                    continue

                close = hist["Close"].values
                vol   = hist["Volume"].values
                precio = float(close[-1])

                # v17 Fix AMD-F3: DD medido desde pico de 52 semanas
                # Antes: pico solo desde los Гәltimos 3 meses вҶ’ subestimaba la correcciГіn
                # Ahora: pico real de 52 semanas para DD correcto
                try:
                    import datetime as _dt_52w
                    _e52 = _dt_52w.date.today()
                    _s52 = _e52 - _dt_52w.timedelta(days=365)
                    hist_52w = yf.Ticker(tk).history(
                        start=_s52.strftime("%Y-%m-%d"),
                        end=_e52.strftime("%Y-%m-%d"))
                    pico = float(hist_52w["Close"].max()) if not hist_52w.empty else float(close.max())
                except Exception:
                    pico = float(close.max())

                dd = round((precio - pico) / pico * 100, 1)

                # Filtro DD - correcciГіn real
                if dd > dd_min:
                    continue

                # RSI
                import pandas as _pd_d
                s = _pd_d.Series(close)
                delta = s.diff()
                gain = delta.clip(lower=0).rolling(14).mean()
                loss = (-delta.clip(upper=0)).rolling(14).mean()
                rsi = round(float(100-100/(1+gain.iloc[-1]/(loss.iloc[-1]+1e-9))), 1)

                if not (rsi_min <= rsi <= rsi_max):
                    continue

                # Volumen
                avg_v = float(import_np().mean(vol[-20:]))
                vol_ratio = int(vol[-1] / avg_v * 100) if avg_v > 0 else 100
                if avg_v < 200_000:
                    continue

                # Momentum 3d
                mom_3d = round((close[-1]/close[-4]-1)*100, 2) if len(close)>=4 else 0

                # DГӯas bajistas (para M1 - aГәn cayendo)
                dias_bajistas = 0
                for _i in range(1, min(5, len(close))):
                    if close[-_i] < close[-_i-1]:
                        dias_bajistas += 1
                    else:
                        break

                # Score Rebote
                sr = calcular_score_rebote(
                    dd=dd, rsi=rsi, vol_ratio=vol_ratio,
                    dias_alcistas=0, momentum_3d=mom_3d,
                    tiene_catalizador=False, dias_para_cat=999,
                    beta=1.5
                )
                if sr["score"] < score_min:
                    continue

                # Prob NBIS
                prob = calcular_prob_nbis(
                    rsi=rsi, vol_ratio=vol_ratio, dd=dd,
                    dias_alcistas=0, momentum_3d=mom_3d,
                    tiene_catalizador=False
                )
                if prob < 20:
                    continue

                # Etapa v12
                # v16 fix: obtener earnings live + area real desde yfinance info
                try:
                    _info_d1 = yf.Ticker(tk).info or {}
                except Exception:
                    _info_d1 = {}

                # ГҒrea real desde sector
                _sector_d1 = _info_d1.get("sector", "-")
                _sector_map_d1 = {
                    "Technology":"Tech","Healthcare":"Salud",
                    "Financial Services":"Finanzas",
                    "Consumer Cyclical":"Consumo",
                    "Consumer Defensive":"Consumo",
                    "Energy":"EnergГӯa","Industrials":"Industrial",
                    "Communication Services":"Tech",
                    "Basic Materials":"Materiales",
                    "Real Estate":"Real Estate",
                }
                _area_d1 = _sector_map_d1.get(_sector_d1,
                           _sector_d1[:10] if _sector_d1 and _sector_d1 != "-" else "-")

                # Earnings live вҖ” usar get_earnings_single() con cache
                _cat_fecha_d1 = get_earnings_single(tk)

                # Etapa con earnings real
                etapa = clasificar_etapa_v12(
                    rsi=rsi, vol_ratio=vol_ratio, prob_nbis=prob,
                    dias_alcistas=0, momentum_3d=mom_3d,
                    score_rebote=sr["score"], dd=dd,
                    cat_fecha=_cat_fecha_d1
                )

                # Sympathy data
                _symp_d1 = get_sympathy(tk)

                candidatos.append({
                    "Ticker":        tk,
                    "Precio":        round(precio, 2),
                    "DD_pico":       dd,
                    "RSI":           rsi,
                    "Div_RSI":       _div_sw.get("tipo","none"),
                    "Div_Badge":     _div_sw.get("badge",""),
                    "Div_Desc":      _div_sw.get("descripcion",""),
                    "Volumen":       vol_ratio,
                    "Momentum_3d":   mom_3d,
                    "Dias_Bajistas": dias_bajistas,
                    "Score_Rebote":  sr["score"],
                    "Nivel_Rebote":  sr["nivel"],
                    "Detalle_Rebote":sr["detalle"],
                    "Prob_NBIS":     prob,
                    "Etapa_v12":     etapa["label"],
                    "Decision":      "SEGUIR",
                    "Fase":          "M1",
                    "Area":          _area_d1,        # v16 fix: ГЎrea real
                    "Motivo":        f"CorrecciГіn {dd}% В· RSI {rsi} В· Prob {prob}%",
                    "Lectura":       etapa["accion"],
                    "Score":         sr["score"],
                    "Cat_Fecha":     _cat_fecha_d1,   # v16 fix: earnings live
                    "Cat_Desc":      _info_d1.get("longBusinessSummary","")[:80] if _cat_fecha_d1 != "-" else "-",
                    "Cat_Tipo":      "Earnings" if _cat_fecha_d1 != "-" else "-",
                    "Arrastradas":   _symp_d1["arrastradas"],
                    "Lider":         _symp_d1["lider"],
                    "Color":         "#" + etapa["color"],
                    "Bg":            "#" + etapa["bg"],
                })
            except Exception:
                continue
    except Exception:
        pass

    if not candidatos:
        return pd.DataFrame()

    try:
        df_d = pd.DataFrame(candidatos)
        # Ordenar por DD mГЎs profundo primero
        df_d = df_d.sort_values("DD_pico", ascending=True)
        return df_d.head(max_results)
    except Exception:
        return pd.DataFrame()


# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
#  MГ“DULO BACKTESTING v13
#  Soporte/Resistencia + Backtesting 6 meses automГЎtico
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

def calcular_soporte_resistencia(close: list, high: list, low: list) -> dict:
    """
    Calcula niveles de soporte y resistencia tГ©cnicos.
    Usa pivots, EMA200 y rangos de 52 semanas.
    """
    import numpy as np
    close = list(close)
    high  = list(high)
    low   = list(low)
    n     = len(close)

    # EMA200
    ema200 = None
    if n >= 200:
        import pandas as _pd_sr
        ema200 = float(_pd_sr.Series(close).ewm(span=200).mean().iloc[-1])

    # Soporte/Resistencia 52 semanas
    n_aГұo = min(252, n)
    max_aГұo = max(high[-n_aГұo:])
    min_aГұo = min(low[-n_aГұo:])

    # Pivot Points Гәltimos 20 dГӯas
    pivots_sup = []
    pivots_inf = []
    for i in range(2, min(20, n-2)):
        idx = -(i+1)
        if high[idx] > high[idx-1] and high[idx] > high[idx+1]:
            pivots_sup.append(high[idx])
        if low[idx] < low[idx-1] and low[idx] < low[idx+1]:
            pivots_inf.append(low[idx])

    precio = close[-1]

    # Soporte mГЎs cercano por debajo del precio
    soportes = sorted([x for x in pivots_inf if x < precio], reverse=True)
    soporte_cercano = soportes[0] if soportes else min_aГұo

    # Resistencia mГЎs cercana por encima
    resistencias = sorted([x for x in pivots_sup if x > precio])
    resistencia_cercana = resistencias[0] if resistencias else max_aГұo

    # ВҝPrecio cerca de soporte? (dentro del 3%)
    cerca_soporte = abs(precio - soporte_cercano) / precio < 0.03 if soporte_cercano else False
    cerca_resistencia = abs(precio - resistencia_cercana) / precio < 0.03 if resistencia_cercana else False

    # Sobre o bajo EMA200
    sobre_ema200 = precio > ema200 if ema200 else None

    return {
        "soporte":           round(soporte_cercano, 2),
        "resistencia":       round(resistencia_cercana, 2),
        "min_52s":           round(min_aГұo, 2),
        "max_52s":           round(max_aГұo, 2),
        "ema200":            round(ema200, 2) if ema200 else None,
        "cerca_soporte":     cerca_soporte,
        "cerca_resistencia": cerca_resistencia,
        "sobre_ema200":      sobre_ema200,
        "dist_soporte_pct":  round((precio - soporte_cercano) / precio * 100, 1),
        "dist_resist_pct":   round((resistencia_cercana - precio) / precio * 100, 1),
    }


def backtest_ticker(tk: str, meses: int = 6) -> list:
    """
    Backtesting automГЎtico para un ticker.
    Simula seГұales M2/M3 en los Гәltimos N meses
    y verifica si rebotaron +8% / +12% en 10 dГӯas.
    """
    import yfinance as yf
    import pandas as pd
    import numpy as np

    resultados = []
    try:
        hist = yf.Ticker(tk).history(period=f"{meses}mo")
        if hist.empty or len(hist) < 60:
            return []

        close_arr = hist["Close"].values
        vol_arr   = hist["Volume"].values
        high_arr  = hist["High"].values
        low_arr   = hist["Low"].values
        dates     = hist.index.tolist()
        n         = len(close_arr)

        # Necesitamos al menos 20 dГӯas de historia + 10 dГӯas de resultado
        for i in range(20, n - 10):
            close_h = close_arr[:i+1]
            vol_h   = vol_arr[:i+1]
            high_h  = high_arr[:i+1]
            low_h   = low_arr[:i+1]

            precio  = float(close_h[-1])
            pico    = float(close_h.max())
            dd      = round((precio - pico) / pico * 100, 1)

            if dd > -5:  # sin correcciГіn suficiente
                continue

            # RSI
            s     = pd.Series(close_h)
            delta = s.diff()
            gain  = delta.clip(lower=0).rolling(14).mean()
            loss  = (-delta.clip(upper=0)).rolling(14).mean()
            rsi   = float(100 - 100/(1 + gain.iloc[-1]/(loss.iloc[-1]+1e-9)))

            if not (25 <= rsi <= 65):
                continue

            # Volumen ratio
            avg_v = float(np.mean(vol_h[-20:]))
            vol_r = int(vol_h[-1] / avg_v * 100) if avg_v > 0 else 100

            # Momentum 3d
            mom = round((close_h[-1]/close_h[-4]-1)*100, 2) if len(close_h)>=4 else 0

            # DГӯas alcistas
            dias_alc = 0
            for _j in range(1, min(5, len(close_h))):
                if close_h[-_j] > close_h[-_j-1]:
                    dias_alc += 1
                else:
                    break

            # Prob NBIS
            prob = calcular_prob_nbis(
                rsi=rsi, vol_ratio=vol_r, dd=dd,
                dias_alcistas=dias_alc, momentum_3d=mom,
                tiene_catalizador=False
            )

            # Soporte/Resistencia
            sr = calcular_soporte_resistencia(close_h, high_h, low_h)

            # Clasificar fase
            if rsi <= 35 and dias_alc >= 3 and mom >= 5 and vol_r >= 60:
                fase = "M3"
            elif 30 <= rsi <= 45 and dias_alc >= 1 and mom >= 1 and vol_r >= 50:
                fase = "M2"
            else:
                continue

            # Simular resultado en los 10 dГӯas siguientes
            precio_entrada = precio
            max_alcanzado  = precio_entrada
            stop_activado  = False
            t1_alcanzado   = False
            t2_alcanzado   = False
            resultado_dia10 = 0

            for d in range(1, 11):
                if i + d >= n:
                    break
                p_dia = float(close_arr[i + d])
                pnl   = (p_dia - precio_entrada) / precio_entrada * 100
                max_alcanzado = max(max_alcanzado, p_dia)

                if pnl <= -7:
                    stop_activado = True
                    resultado_dia10 = pnl
                    break
                if pnl >= 12:
                    t2_alcanzado = True
                    t1_alcanzado = True
                if pnl >= 8:
                    t1_alcanzado = True

                if d == 10:
                    resultado_dia10 = pnl

            ganadora = t1_alcanzado and not stop_activado

            # v16: ATR real en el punto de entrada + stop real calculado
            try:
                atr_val = float(np.mean(
                    np.maximum(
                        high_h[-14:] - low_h[-14:],
                        np.maximum(
                            abs(high_h[-14:] - close_h[-15:-1]),
                            abs(low_h[-14:]  - close_h[-15:-1])
                        )
                    )
                )) if len(high_h) >= 15 else precio_entrada * 0.03
            except Exception:
                atr_val = precio_entrada * 0.03

            stop_atr    = round(precio_entrada - atr_val * 1.5, 2)
            stop_pct_bt = round(atr_val * 1.5 / precio_entrada * 100, 1)
            precio_max  = round(float(max_alcanzado), 2)
            precio_salida = round(float(close_arr[min(i+10, n-1)]), 2)
            resultado_real = round((precio_salida - precio_entrada)/precio_entrada*100, 2)

            resultados.append({
                "Ticker":          tk,
                "Fecha":           str(dates[i])[:10],
                "Fase":            fase,
                "Precio_Entrada":  round(precio_entrada, 2),
                "Precio_Salida":   precio_salida,
                "Precio_Max":      precio_max,
                "RSI":             round(rsi, 1),
        "Div_RSI":         _div_fetch.get("tipo","none"),
        "Div_Badge":       _div_fetch.get("badge",""),
        "Div_Desc":        _div_fetch.get("descripcion",""),
                "DD":              dd,
                "Vol_Ratio":       vol_r,
                "Momentum_3d":     round(mom, 1),
                "Dias_Alcistas":   dias_alc,
                "Prob_NBIS":       prob,
                "Cerca_Soporte":   sr["cerca_soporte"],
                "Dist_Soporte":    sr["dist_soporte_pct"],
                "ATR_Entrada":     round(atr_val, 2),
                "Stop_ATR":        stop_atr,
                "Stop_Pct":        stop_pct_bt,
                "Resultado_10d":   round(resultado_dia10, 2),
                "Resultado_Real":  resultado_real,
                "T1_Alcanzado":    t1_alcanzado,
                "T2_Alcanzado":    t2_alcanzado,
                "Stop_Activado":   stop_activado,
                "Ganadora":        ganadora,
            })

    except Exception:
        pass

    return resultados



# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  BACKTESTING REAL v16
#  Usa precios histГіricos reales de entrada y salida
#  Calcula win rate, avg gain, avg loss y ratio R/R verdaderos
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
@st.cache_data(ttl=3600, show_spinner=False)
def backtest_real_v16(ticker: str, meses: int = 6,
                      stop_atr_mult: float = 1.5,
                      target1_pct: float = 8.0,
                      target2_pct: float = 15.0,
                      dias_max: int = 15) -> dict:
    """
    Backtesting real v16 - calcula win rate con precios exactos.

    Para cada seГұal M2/M3 detectada en el perГӯodo:
    - Precio entrada = Close del dГӯa de seГұal
    - Stop = Close - (ATR x 1.5) calculado en ese momento
    - Target 1 = +8%, Target 2 = +15%
    - Salida = primer evento que ocurra en dГӯas_max dГӯas

    Retorna estadГӯsticas reales:
    - win_rate, avg_ganancia, avg_perdida, ratio_rr, expectativa
    """
    import yfinance as yf, numpy as np, pandas as pd

    resultado_base = {
        "ticker": ticker, "n_seГұales": 0, "n_ganadoras": 0,
        "n_perdedoras": 0, "win_rate": 0, "avg_ganancia": 0,
        "avg_perdida": 0, "ratio_rr": 0, "expectativa": 0,
        "max_ganancia": 0, "max_perdida": 0,
        "trades": [], "_ok": False, "error": ""
    }

    try:
        hist = yf.Ticker(ticker).history(period=f"{meses}mo")
        if hist is None or len(hist) < 60:
            resultado_base["error"] = "Insuficientes datos histГіricos"
            return resultado_base

        close = hist["Close"].values
        high  = hist["High"].values
        low   = hist["Low"].values
        vol   = hist["Volume"].values
        dates = [str(d)[:10] for d in hist.index.tolist()]
        n     = len(close)

        trades = []

        for i in range(20, n - dias_max - 1):
            ch = close[:i+1]
            vh = vol[:i+1]
            hh = high[:i+1]
            lh = low[:i+1]

            precio = float(ch[-1])
            pico   = float(ch.max())
            dd     = round((precio - pico) / pico * 100, 1)
            if dd > -5:
                continue

            # RSI
            s     = pd.Series(ch)
            delta = s.diff()
            gain  = delta.clip(lower=0).rolling(14).mean()
            loss  = (-delta.clip(upper=0)).rolling(14).mean()
            rsi   = float(100 - 100/(1 + gain.iloc[-1]/(loss.iloc[-1]+1e-9)))
            if not (25 <= rsi <= 55):
                continue

            # Volumen
            avg_v = float(np.mean(vh[-20:])) if len(vh) >= 20 else float(vh[-1])
            vol_r = int(vh[-1] / avg_v * 100) if avg_v > 0 else 100
            if vol_r < 50:
                continue

            # DГӯas alcistas
            dias_alc = 0
            for j in range(1, min(5, len(ch))):
                if ch[-j] > ch[-j-1]: dias_alc += 1
                else: break
            if dias_alc < 2:
                continue

            # Momentum
            mom = round((ch[-1]/ch[-4]-1)*100, 2) if len(ch) >= 4 else 0

            # Fase
            if rsi <= 42 and dias_alc >= 3 and mom >= 3 and vol_r >= 50 and dd <= -8:
                fase = "M3"
            elif 30 <= rsi <= 45 and dias_alc >= 2 and mom >= 1 and vol_r >= 50 and dd <= -8:
                fase = "M2"
            else:
                continue

            # ATR real en el momento de la seГұal
            if i >= 15:
                tr_list = []
                for k in range(i-13, i+1):
                    hl  = float(hh[k]) - float(lh[k])
                    hcp = abs(float(hh[k]) - float(ch[k-1]))
                    lcp = abs(float(lh[k]) - float(ch[k-1]))
                    tr_list.append(max(hl, hcp, lcp))
                atr_actual = float(np.mean(tr_list))
            else:
                atr_actual = precio * 0.025  # fallback 2.5%

            stop_dist   = round(atr_actual * stop_atr_mult, 4)
            stop_precio = round(precio - stop_dist, 2)
            t1_precio   = round(precio * (1 + target1_pct/100), 2)
            t2_precio   = round(precio * (1 + target2_pct/100), 2)

            # Simular resultado real en dГӯas siguientes
            precio_salida  = None
            pnl_pct        = 0.0
            razon_salida   = "timeout"
            dia_salida     = dias_max

            for d in range(1, dias_max + 1):
                if i + d >= n:
                    precio_salida = float(close[i + d - 1])
                    razon_salida  = "fin datos"
                    dia_salida    = d
                    break
                p_low  = float(low[i + d])
                p_high = float(high[i + d])
                p_close= float(close[i + d])

                # Stop activado (bajo del dГӯa toca stop)
                if p_low <= stop_precio:
                    precio_salida = stop_precio
                    razon_salida  = "stop"
                    dia_salida    = d
                    break
                # Target 2 alcanzado
                if p_high >= t2_precio:
                    precio_salida = t2_precio
                    razon_salida  = "T2 +15%"
                    dia_salida    = d
                    break
                # Target 1 alcanzado
                if p_high >= t1_precio:
                    precio_salida = t1_precio
                    razon_salida  = "T1 +8%"
                    dia_salida    = d
                    break
                # Timeout - salir al cierre del Гәltimo dГӯa
                if d == dias_max:
                    precio_salida = p_close
                    razon_salida  = f"timeout {dias_max}d"
                    dia_salida    = d

            if precio_salida is None:
                precio_salida = float(close[min(i + dias_max, n-1)])

            pnl_pct  = round((precio_salida - precio) / precio * 100, 2)
            ganadora = pnl_pct > 0

            trades.append({
                "Ticker":         ticker,
                "Fecha":          dates[i],
                "Fase":           fase,
                "Precio_Entrada": round(precio, 2),
                "Precio_Salida":  round(precio_salida, 2),
                "PnL_pct":        pnl_pct,
                "Razon_Salida":   razon_salida,
                "Dia_Salida":     dia_salida,
                "ATR":            round(atr_actual, 2),
                "Stop":           stop_precio,
                "T1":             t1_precio,
                "T2":             t2_precio,
                "RSI":            round(rsi, 1),
                "DD":             dd,
                "Vol_Ratio":      vol_r,
                "Ganadora":       ganadora,
            })

        if not trades:
            resultado_base["error"] = "Sin seГұales detectadas en el perГӯodo"
            return resultado_base

        # EstadГӯsticas reales
        n_tot  = len(trades)
        n_win  = sum(1 for t in trades if t["Ganadora"])
        n_lose = n_tot - n_win
        ganancias = [t["PnL_pct"] for t in trades if t["Ganadora"]]
        perdidas  = [t["PnL_pct"] for t in trades if not t["Ganadora"]]

        avg_g   = round(float(np.mean(ganancias)), 2) if ganancias else 0
        avg_p   = round(float(np.mean(perdidas)), 2) if perdidas else 0
        max_g   = round(max(ganancias), 2) if ganancias else 0
        max_p   = round(min(perdidas), 2) if perdidas else 0
        win_r   = round(n_win / n_tot * 100, 1)
        ratio   = round(abs(avg_g / avg_p), 2) if avg_p != 0 else 0
        # Expectativa = win% x avg_gain + lose% x avg_loss
        expectativa = round((n_win/n_tot) * avg_g + (n_lose/n_tot) * avg_p, 2) if n_tot > 0 else 0

        return {
            "ticker": ticker, "n_seГұales": n_tot,
            "n_ganadoras": n_win, "n_perdedoras": n_lose,
            "win_rate": win_r, "avg_ganancia": avg_g,
            "avg_perdida": avg_p, "ratio_rr": ratio,
            "expectativa": expectativa,
            "max_ganancia": max_g, "max_perdida": max_p,
            "trades": trades, "_ok": True, "error": "",
        }

    except Exception as e:
        resultado_base["error"] = str(e)
        return resultado_base

@st.cache_data(ttl=3600, show_spinner=False)
def run_backtesting(tickers: tuple, meses: int = 6) -> "pd.DataFrame":
    """Ejecuta backtesting para lista de tickers. Retorna DataFrame con resultados."""
    import pandas as pd
    todos = []
    for tk in tickers:
        todos.extend(backtest_ticker(tk, meses))
    if not todos:
        return pd.DataFrame()
    return pd.DataFrame(todos)


# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
#  BACKTESTING PATRГ“N NBIS EXACTO v13
#  Criterios: RSI <= 35  - Mom >= +7%  - DD <= -15%  - Vol >= 150%
#  Referencia NBIS: RSI 38, Vol 280%, DD -55%, Mom +27%
# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
NBIS_CRITERIOS = {
    "rsi_max":       35.0,   # RSI <= 35
    "mom_min":        7.0,   # Momentum 3d >= +7%
    "dd_max":       -15.0,   # DD <= -15%
    "vol_min":      150.0,   # Volumen >= 150% del promedio
    "dias_alc_min":   2,     # MГӯnimo 2 dГӯas alcistas
    "stop":          -7.0,   # Stop -7%
    "t1":             8.0,   # Target 1 +8%
    "t2":            12.0,   # Target 2 +12%
    "dias_max":      10,     # MГЎximo 10 dГӯas
}

@st.cache_data(ttl=7200, show_spinner=False)
def run_backtesting_nbis(tickers: tuple, meses: int = 6) -> "pd.DataFrame":
    """
    Backtesting con criterios exactos del patrГіn NBIS.
    MГЎs estricto que el backtesting general.
    """
    import yfinance as yf
    import pandas as pd
    import numpy as np

    todos = []
    cr    = NBIS_CRITERIOS

    for tk in tickers:
        try:
            hist = yf.Ticker(tk).history(period=f"{meses}mo")
            if hist.empty or len(hist) < 60:
                continue

            close = hist["Close"].values
            vol   = hist["Volume"].values
            high  = hist["High"].values
            low   = hist["Low"].values
            dates = hist.index.tolist()
            n     = len(close)

            for i in range(20, n - 10):
                cl_h  = close[:i+1]
                vol_h = vol[:i+1]

                # DD
                precio = float(cl_h[-1])
                pico   = float(cl_h.max())
                dd     = round((precio - pico) / pico * 100, 1)
                if dd > cr["dd_max"]:
                    continue

                # RSI
                import pandas as _pd
                s     = _pd.Series(cl_h)
                delta = s.diff()
                gain  = delta.clip(lower=0).rolling(14).mean()
                loss  = (-delta.clip(upper=0)).rolling(14).mean()
                rsi   = float(100-100/(1+gain.iloc[-1]/(loss.iloc[-1]+1e-9)))
                if rsi > cr["rsi_max"]:
                    continue

                # Momentum 3d
                mom = round((cl_h[-1]/cl_h[-4]-1)*100, 2) if len(cl_h)>=4 else 0
                if mom < cr["mom_min"]:
                    continue

                # Volumen
                avg_v = float(np.mean(vol_h[-20:]))
                vol_r = int(vol_h[-1]/avg_v*100) if avg_v > 0 else 0
                if vol_r < cr["vol_min"]:
                    continue

                # DГӯas alcistas
                dias_alc = 0
                for _j in range(1, min(5, len(cl_h))):
                    if cl_h[-_j] > cl_h[-_j-1]:
                        dias_alc += 1
                    else:
                        break
                if dias_alc < cr["dias_alc_min"]:
                    continue

                # Prob NBIS
                prob = calcular_prob_nbis(
                    rsi=rsi, vol_ratio=vol_r, dd=dd,
                    dias_alcistas=dias_alc, momentum_3d=mom,
                    tiene_catalizador=False
                )

                # Soporte/Resistencia
                sr_data = calcular_soporte_resistencia(cl_h, high[:i+1], low[:i+1])

                # Simular resultado 10 dГӯas
                precio_e   = precio
                stop_act   = False
                t1_act     = False
                t2_act     = False
                res_10d    = 0
                precio_max = precio_e

                for d in range(1, 11):
                    if i+d >= n:
                        break
                    p_d = float(close[i+d])
                    pnl = (p_d - precio_e) / precio_e * 100
                    precio_max = max(precio_max, p_d)

                    if pnl <= cr["stop"]:
                        stop_act = True
                        res_10d  = pnl
                        break
                    if pnl >= cr["t2"]:
                        t2_act = True
                        t1_act = True
                    if pnl >= cr["t1"]:
                        t1_act = True
                    if d == 10:
                        res_10d = pnl

                ganadora = t1_act and not stop_act

                todos.append({
                    "Ticker":          tk,
                    "Fecha":           str(dates[i])[:10],
                    "RSI":             round(rsi, 1),
                    "DD":              dd,
                    "Momentum_3d":     round(mom, 1),
                    "Vol_Ratio":       vol_r,
                    "Dias_Alcistas":   dias_alc,
                    "Prob_NBIS":       prob,
                    "Precio_Entrada":  round(precio_e, 2),
                    "Cerca_Soporte":   sr_data["cerca_soporte"],
                    "EMA200":          sr_data["ema200"],
                    "Sobre_EMA200":    sr_data["sobre_ema200"],
                    "Resultado_10d":   round(res_10d, 2),
                    "T1_Alcanzado":    t1_act,
                    "T2_Alcanzado":    t2_act,
                    "Stop_Activado":   stop_act,
                    "Ganadora":        ganadora,
                    "Max_Alcanzado_Pct": round((precio_max-precio_e)/precio_e*100, 1),
                })
        except Exception:
            continue

    if not todos:
        return pd.DataFrame()
    return pd.DataFrame(todos)

def render_noticias_mini(tickers: list, titulo: str = "рҹ“° Noticias del mercado"):
    """
    Panel compacto de noticias para Swing Activo y Mis Posiciones.
    Muestra las Гәltimas 2-3 noticias por acciГіn con su sentimiento.
    """
    news_cache = st.session_state.get("noticias_cache", {})
    if not news_cache:
        st.markdown(
            f'<div style="background:#1E3A5F;border-radius:8px 8px 0 0;padding:8px 14px">'
            f'<span style="font-size:12px;font-weight:700;color:white">рҹ“° NOTICIAS DEL MERCADO</span>'
            f'</div>'
            f'<div style="background:{BG_HEAD};border:1px solid {BOR};border-radius:0 0 8px 8px;'
            f'padding:10px 14px;font-size:11px;color:{TXT_MUT}">'
            f'Sin noticias вҖ” presiona "рҹ”„ Actualizar noticias" en el sidebar</div>',
            unsafe_allow_html=True)
        return

    _ts_news = st.session_state.get("noticias_actualizadas", "-")
    st.markdown(
        f'<div style="background:#1E3A5F;border-radius:8px 8px 0 0;'
        f'padding:8px 14px;display:flex;justify-content:space-between;'
        f'align-items:center">'
        f'<div style="font-size:12px;font-weight:700;color:white">'
        f'рҹ“° NOTICIAS DEL MERCADO</div>'
        f'<div style="font-size:10px;color:#93C5FD">Гҡltima actualizaciГіn: {_ts_news}</div>'
        f'</div>',
        unsafe_allow_html=True)

    tickers_con_noticias = [tk for tk in tickers if tk in news_cache and news_cache[tk]["noticias"]]

    if not tickers_con_noticias:
        st.markdown(
            f'<div style="font-size:10px;color:{TXT_MUT}">Sin noticias disponibles para estas acciones</div>',
            unsafe_allow_html=True)
        return

    for tk in tickers_con_noticias[:8]:  # mГЎximo 8 acciones
        data     = news_cache[tk]
        noticias = data["noticias"][:3]   # mГЎximo 3 noticias por acciГіn
        bonus    = data.get("bonus", 0)
        if not noticias:
            continue

        bonus_c = G if bonus > 5 else R if bonus < -5 else TXT_MUT
        bonus_s = f"+{bonus}" if bonus > 0 else str(bonus)

        st.markdown(
            f'<div style="background:{BG_CARD};border:1px solid {BOR};'+
            f'border-left:3px solid {bonus_c};border-radius:8px;'+
            f'padding:8px 12px;margin-bottom:6px">'+
            f'<div style="display:flex;justify-content:space-between;margin-bottom:4px">'+
            f'<span style="font-size:12px;font-weight:800;color:{B}">{tk}</span>'+
            f'<span style="font-size:10px;font-weight:700;color:{bonus_c}">'+
            f'Sentimiento: {bonus_s}</span>'+
            f'</div>',
            unsafe_allow_html=True)

        for noticia in noticias:
            titulo_n = _ascii(str(noticia.get("titulo", "")))[:80]
            fuente_n = _ascii(str(noticia.get("fuente","Yahoo")))
            sent_c   = G if noticia.get("sentimiento","") == "positivo" else \
                       R if noticia.get("sentimiento","") == "negativo" else TXT_MUT
            sent_s   = "в–І" if noticia.get("sentimiento","") == "positivo" else \
                       "в–ј" if noticia.get("sentimiento","") == "negativo" else "в—Ҹ"
            link     = noticia.get("link","#")
            if titulo_n:
                st.markdown(
                    f'<div style="font-size:10px;color:{TXT};margin:2px 0;padding-left:8px">'+
                    f'<span style="color:{sent_c};font-weight:700">{sent_s}</span> '+
                    f'<a href="{link}" target="_blank" style="color:{TXT};text-decoration:none">'+
                    f'{titulo_n}</a>'+
                    f'<span style="color:{TXT_MUT};font-size:9px">  - {fuente_n}</span>'+
                    f'</div>',
                    unsafe_allow_html=True)

        st.markdown("</div>", unsafe_allow_html=True)


