# v18: leer Sheet IDs desde Streamlit secrets si estГЎn configurados
def _get_sheet_id_from_secrets(key: str) -> str:
    """Lee Sheet ID desde st.secrets[sheets][key] si existe."""
    try:
        return st.secrets["sheets"][key]
    except Exception:
        return ""

