# в”Җв”Җ Estado del mercado (abierto/cerrado/pre/post) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
def get_market_status() -> dict:
    """
    Detecta si el mercado NYSE estГЎ abierto, cerrado, en pre o post market.
    Basado en hora de Nueva York (ET).
    """
    import datetime as _dt
    try:
        import pytz
        ny_tz = pytz.timezone("America/New_York")
        now_ny = _dt.datetime.now(ny_tz)
    except ImportError:
        # Sin pytz вҖ” usar UTC-5 como aproximaciГіn
        now_ny = _dt.datetime.utcnow() - _dt.timedelta(hours=5)

    hora    = now_ny.hour
    minuto  = now_ny.minute
    weekday = now_ny.weekday()  # 0=Lunes, 6=Domingo
    hora_decimal = hora + minuto/60

    # Fin de semana
    if weekday >= 5:
        return {
            "estado":  "cerrado",
            "label":   "рҹ”ҙ Mercado Cerrado вҖ” Fin de semana",
            "detalle": f"Abre el lunes a las 9:30 AM ET",
            "color":   "#DC2626",
            "bg":      "#FEF2F2",
        }
    # Pre-market: 4:00 AM - 9:30 AM ET
    if 4.0 <= hora_decimal < 9.5:
        mins_para_open = int((9.5 - hora_decimal) * 60)
        return {
            "estado":  "pre_market",
            "label":   "рҹҹЎ Pre-Market",
            "detalle": f"Mercado abre en {mins_para_open} min (9:30 AM ET) вҖ” precios orientativos",
            "color":   "#D97706",
            "bg":      "#FFFBEB",
        }
    # Mercado abierto: 9:30 AM - 4:00 PM ET
    if 9.5 <= hora_decimal < 16.0:
        mins_para_close = int((16.0 - hora_decimal) * 60)
        return {
            "estado":  "abierto",
            "label":   "рҹҹў Mercado Abierto",
            "detalle": f"Cierra en {mins_para_close} min (4:00 PM ET)",
            "color":   "#16A34A",
            "bg":      "#F0FDF4",
        }
    # Post-market: 4:00 PM - 8:00 PM ET
    if 16.0 <= hora_decimal < 20.0:
        return {
            "estado":  "post_market",
            "label":   "рҹ”ө Post-Market",
            "detalle": "Mercado cerrado вҖ” solo trading extendido hasta 8:00 PM ET",
            "color":   "#2563EB",
            "bg":      "#EFF6FF",
        }
    # Noche / madrugada
    return {
        "estado":  "cerrado",
        "label":   "рҹ”ҙ Mercado Cerrado",
        "detalle": "Pre-market abre a las 4:00 AM ET",
        "color":   "#DC2626",
        "bg":      "#FEF2F2",
    }

