def detectar_regimen(spy_data: dict, vix_val: float, vix_trend: dict = None) -> dict:
    """
    v19.3 вҖ” Detector de RГ©gimen del Mercado
    Detecta si el viento es a favor, neutro o en contra.
    
    SeГұales de alerta temprana (antes de que el SPY caiga):
      - MACD SPY cruza a negativo (3-7 dГӯas de adelanto)
      - VIX sube >3 puntos en 1 semana (2-5 dГӯas de adelanto)
      - SPY cae bajo EMA200 (confirmaciГіn de bear)
    """
    if not spy_data:
        return {"regimen":"DESCONOCIDO","color":"#64748B","emoji":"вқ“",
                "accion":"Sin datos de mercado","umbral_score":15,"alerta":""}

    _rsi        = spy_data.get("rsi", 55)
    _sobre_e200 = spy_data.get("sobre_ema200", True)
    _dist_e200  = spy_data.get("dist_ema200", 5)
    _macd_cruce = spy_data.get("macd_cruce", "positivo")
    _macd_dir   = spy_data.get("macd_dir", "subiendo")
    _chg_20d    = spy_data.get("chg_20d", 0)
    _vix_trend  = vix_trend or {}
    _vix_subiendo = _vix_trend.get("subiendo", False)
    _vix_chg_7d   = _vix_trend.get("chg_7d", 0)

    # в”Җв”Җ SEГ‘ALES DE ALERTA TEMPRANA в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    _alertas  = []
    _urgencia = 0  # 0=ninguna, 1=precauciГіn, 2=alerta, 3=urgente

    if _macd_cruce == "negativo" and _macd_dir == "bajando":
        _alertas.append("вҡ пёҸ MACD SPY cruzГі a negativo вҖ” viento cambiando")
        _urgencia = max(_urgencia, 2)
    elif _macd_cruce == "negativo":
        _alertas.append("рҹ’Ў MACD SPY negativo pero estabilizando")
        _urgencia = max(_urgencia, 1)

    if _vix_chg_7d > 4:
        _alertas.append(f"рҹҡЁ VIX subiГі +{_vix_chg_7d:.1f}pts en 7 dГӯas вҖ” miedo aumentando")
        _urgencia = max(_urgencia, 2)
    elif _vix_chg_7d > 2:
        _alertas.append(f"вҡ пёҸ VIX subiendo +{_vix_chg_7d:.1f}pts вҖ” vigilar")
        _urgencia = max(_urgencia, 1)

    if _chg_20d < -5:
        _alertas.append(f"рҹҡЁ SPY cayГі {_chg_20d:.1f}% en 20 dГӯas")
        _urgencia = max(_urgencia, 3)
    elif _chg_20d < -2:
        _alertas.append(f"вҡ пёҸ SPY dГ©bil en el mes: {_chg_20d:.1f}%")
        _urgencia = max(_urgencia, 1)

    # в”Җв”Җ CLASIFICACIГ“N DE RГүGIMEN в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    if not _sobre_e200 or (_chg_20d < -7):
        # BEAR: SPY bajo EMA200 o caГӯda fuerte
        return {
            "regimen":       "BEAR",
            "color":         "#EF4444",
            "color_bg":      "#FEF2F2",
            "color_border":  "#FECACA",
            "emoji":         "рҹҗ»",
            "titulo":        "рҹҗ» RГүGIMEN BEAR вҖ” Viento en contra",
            "accion_nbis":   "No entrar NBIS nuevos В· Solo defensa con catalizador excepcional",
            "accion_mom":    "No entrar Momentum В· Alto riesgo de reversiГіn",
            "accion_pos":    "рҹҡЁ Revisar TODOS los stops В· Cristalizar ganancias inmediatamente",
            "umbral_score":  17,
            "alertas":       _alertas,
            "urgencia":      _urgencia,
            "contexto":      f"SPY {'bajo' if not _sobre_e200 else 'dГ©bil'} EMA200 В· MACD {_macd_cruce} В· VIX {vix_val:.0f}",
        }
    elif (_macd_cruce == "negativo" and _macd_dir == "bajando") or          (_vix_chg_7d > 4) or (_chg_20d < -3):
        # ALERTA: seГұales de deterioro, aГәn bull pero cambiando
        return {
            "regimen":       "ALERTA",
            "color":         "#F97316",
            "color_bg":      "#FFF7ED",
            "color_border":  "#FDBA74",
            "emoji":         "вҡ пёҸ",
            "titulo":        "вҡ пёҸ RГүGIMEN CAMBIANDO вҖ” SeГұales de deterioro",
            "accion_nbis":   "Pausar nuevas entradas NBIS В· Solo score вүҘ17 con catalizador fuerte",
            "accion_mom":    "No iniciar nuevas posiciones В· Apretar stops de las existentes",
            "accion_pos":    "вҡЎ Cristalizar 50% de posiciones con PnL > +10% В· Apretar stops",
            "umbral_score":  17,
            "alertas":       _alertas,
            "urgencia":      _urgencia,
            "contexto":      f"MACD SPY {_macd_cruce} y {_macd_dir} В· VIX +{_vix_chg_7d:.1f}pts/sem В· SPY {_chg_20d:.1f}%/20d",
        }
    elif _rsi > 72 or (vix_val < 16 and _rsi > 68):
        # SOBRECOMPRADO: sigue bull pero con riesgo de correcciГіn
        return {
            "regimen":       "SOBRECOMPRADO",
            "color":         "#EAB308",
            "color_bg":      "#FEFCE8",
            "color_border":  "#FDE047",
            "emoji":         "рҹҢЎпёҸ",
            "titulo":        "рҹҢЎпёҸ MERCADO SOBRECOMPRADO вҖ” Ser selectivo",
            "accion_nbis":   "Solo NBIS score вүҘ15 + catalizador real + WR perfil вүҘ70%",
            "accion_mom":    "Solo Momentum RSI вүӨ78 В· RE < 70 В· catalizador activo",
            "accion_pos":    "вҡЎ Mover stops de runners a breakeven В· No cristalizar aГәn",
            "umbral_score":  15,
            "alertas":       _alertas,
            "urgencia":      _urgencia,
            "contexto":      f"SPY RSI {_rsi:.0f} В· VIX {vix_val:.0f} В· +{_dist_e200:.1f}% sobre EMA200",
        }
    elif 55 <= _rsi <= 72 and _sobre_e200 and _macd_cruce == "positivo":
        # BULL NORMAL: condiciones ideales para el modelo
        return {
            "regimen":       "BULL",
            "color":         "#22C55E",
            "color_bg":      "#F0FDF4",
            "color_border":  "#86EFAC",
            "emoji":         "рҹҡҖ",
            "titulo":        "рҹҡҖ BULL MARKET NORMAL вҖ” Condiciones favorables",
            "accion_nbis":   "Operar NBIS con score вүҘ13 + WR perfil вүҘ65%",
            "accion_mom":    "Operar Momentum con score вүҘ13 В· RSI acciГіn вүӨ80",
            "accion_pos":    "вң… Mantener posiciones В· Stops normales В· Buscar runners",
            "umbral_score":  13,
            "alertas":       _alertas,
            "urgencia":      _urgencia,
            "contexto":      f"SPY RSI {_rsi:.0f} В· MACD+ В· +{_dist_e200:.1f}% sobre EMA200",
        }
    else:
        # NEUTRO
        return {
            "regimen":       "NEUTRO",
            "color":         "#64748B",
            "color_bg":      "#F8FAFC",
            "color_border":  "#CBD5E1",
            "emoji":         "вҡЎ",
            "titulo":        "вҡЎ MERCADO NEUTRO вҖ” Selectivo por ticker",
            "accion_nbis":   "NBIS score вүҘ15 + catalizador confirmado",
            "accion_mom":    "Momentum solo si RSI acciГіn вүӨ75 y hay catalizador claro",
            "accion_pos":    "рҹ“Ҡ Mantener posiciones con catalizador В· Revisar sin catalizador",
            "umbral_score":  15,
            "alertas":       _alertas,
            "urgencia":      _urgencia,
            "contexto":      f"SPY RSI {_rsi:.0f} В· MACD {_macd_cruce} В· VIX {vix_val:.0f}",
        }


