    @st.cache_data(ttl=3600, show_spinner=False)
    def _get_etf_temp(etf_ticker: str) -> dict:
        """Retorna cambio 30d del ETF sectorial вҖ” solo informativo."""
        try:
            import yfinance as _yf_etf
            _h = _yf_etf.Ticker(etf_ticker).history(period="40d")["Close"].dropna()
            if len(_h) < 5: return {"chg30":0,"ok":False}
            return {"chg30":round(float((_h.iloc[-1]-_h.iloc[0])/_h.iloc[0]*100),1),"ok":True}
        except Exception: return {"chg30":0,"ok":False}

    # в”Җв”Җ C-SCORE: Calidad del Catalizador (v19.3) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Combina tГ©cnica con narrativa В· 0-100 В· complementa Score MVALLE
    # Fase 1: componentes gratuitos yfinance (C1,C2,C4,C6,C7,C8)
    # Fase 2: componentes IA (C3,C5) вҖ” opcionales, llamados con botГіn

